$powershellexe = (get-process -id $PID).mainmodule.filename

Describe "Clone array" -Tags "CI" {
    It "Cast in target expr" {
        (([int[]](42)).clone()) | Should -Be 42
        (([int[]](1..5)).clone()).Length | Should -Be 5
        (([int[]](1..5)).clone()).GetType() | Should -Be ([int[]])

    }
    It "Cast not in target expr" {
        $e = [int[]](42)
        $e.Clone() | Should -Be 42
        $e = [int[]](1..5)
        $e.Clone().Length | Should -Be 5
        $e.Clone().GetType() | Should -Be ([int[]])
    }
}

Describe "Set fields through PSMemberInfo" -Tags "CI" {
    Add-Type @"
    public struct AStruct { public string s; }
"@

    It "via cast" {
        ([AStruct]@{s = "abc" }).s | Should -BeExactly "abc"
    }
    It "via new-object" {
        (new-object AStruct -prop @{s="abc"}).s | Should -BeExactly "abc"
    }
    It "via PSObject" {
        $x = [AStruct]::new()
        $x.psobject.properties['s'].Value = 'abc'
        $x.s | Should -Be "abc"
    }
}

Describe "MSFT:3309783" -Tags "CI" {

    It "Run in another process" {


        & $powershellexe -noprofile -command "[psobject] | ForEach-Object FullName" | Should -Be System.Management.Automation.PSObject
    }

    It "Run in current process" {

        [psobject] | ForEach-Object FullName | Should -Be System.Management.Automation.PSObject
    }

    It "Pipe objects derived from PSObject" {

        class MyPsObj : PSObject
        {
            MyPsObj($obj) : base($obj) { }
            [string] ToString() {

                return "MyObj: " + $this.psobject.BaseObject
            }
        }

        [MyPsObj]::new("abc").psobject.ToString() | Should -Be "MyObj: abc"
        [MyPsObj]::new("def") | Out-String | ForEach-Object Trim | Should -Be "MyObj: def"
    }
}

Describe "ScriptBlockAst.GetScriptBlock throws on error" -Tags "CI" {

    $e = $null

    It "with parse error" {
        $ast = [System.Management.Automation.Language.Parser]::ParseInput('function ', [ref]$null, [ref]$e)
        { $ast.GetScriptBlock() } | Should -Throw -ErrorId "PSInvalidOperationException"
    }

    It "with semantic errors" {
        $ast = [System.Management.Automation.Language.Parser]::ParseInput('function foo{param()begin{}end{[ref][ref]1}dynamicparam{}}', [ref]$null, [ref]$e)

        { $ast.GetScriptBlock() } | Should -Throw -ErrorId "PSInvalidOperationException"
        { $ast.EndBlock.Statements[0].Body.GetScriptBlock() } | Should -Throw -ErrorId "PSInvalidOperationException"
    }
}

Describe "Hashtable key property syntax" -Tags "CI" {
    $script = @'

    $hash = New-Object hashtable
    $key = [ConsoleColor]::Red
    $null = $hash.$key
    $hash = @{}
    $hash.$key = 'Hello'

    $hash.$key
'@

    It "In current process" {


        Invoke-Expression $script | Should -BeExactly 'Hello'
    }

    It "In different process" {

        $bytes = [System.Text.Encoding]::Unicode.GetBytes($script)
        & $powershellexe -noprofile -encodedCommand ([Convert]::ToBase64String($bytes)) | Should -BeExactly 'Hello'
    }
}

Describe "Assign automatic variables" -Tags "CI" {

    $autos = '_', 'args', 'this', 'input', 'pscmdlet', 'psboundparameters', 'myinvocation', 'psscriptroot', 'pscommandpath'

    foreach ($auto in $autos)
    {
        It "Assign auto w/ invalid type constraint - $auto" {
            { & ([ScriptBlock]::Create("[datetime]`$$auto = 1")) } | Should -Throw $auto
            { . ([ScriptBlock]::Create("[datetime]`$$auto = 1")) } | Should -Throw $auto
            { & ([ScriptBlock]::Create("[runspace]`$$auto = 1")) } | Should -Throw $auto
            { . ([ScriptBlock]::Create("[runspace]`$$auto = 1")) } | Should -Throw $auto
            { & ([ScriptBlock]::Create("[notexist]`$$auto = 1")) } | Should -Throw $auto
            { . ([ScriptBlock]::Create("[notexist]`$$auto = 1")) } | Should -Throw $auto
        }
    }

    foreach ($auto in $autos)
    {
        It "Assign auto w/o type constraint - $auto" {
            & ([ScriptBlock]::Create("`$$auto = 1; `$$auto")) | Should -Be 1
            . ([ScriptBlock]::Create("`$$auto = 1; `$$auto")) | Should -Be 1
        }
    }

    It "Assign auto w/ correct type constraint" {
        & { [object]$_ = 1; $_ } | Should -Be 1
        & { [object[]]$args = 1; $args } | Should -Be 1
        & { [object]$this = 1; $this } | Should -Be 1
        & { [object]$input = 1; $input } | Should -Be 1

        & { [System.Management.Automation.InvocationInfo]$myInvocation = $myInvocation; $myInvocation.Line } | Should -Match Automation.InvocationInfo
        & { [string]$PSScriptRoot = 'abc'; $PSScriptRoot } | Should -BeExactly 'abc'
        & { [string]$PSCommandPath = 'abc'; $PSCommandPath } | Should -BeExactly 'abc'
    }
}

Describe "Assign readonly/constant variables" -Tags "CI" {

    $testCase = @(
        @{ sb_wo_conversion = { $? = 1 }; name = '$? = 1' }
        @{ sb_wo_conversion = { $HOME = 1 }; name = '$HOME = 1' }
        @{ sb_wo_conversion = { $PID = 1 }; name = '$PID = 1' }
    )

    It "Assign readonly/constant variables w/o type constraint - '<name>'" -TestCases $testCase {
        param($sb_wo_conversion)
        { & $sb_wo_conversion } | Should -Throw -ErrorId "VariableNotWritable"
        { . $sb_wo_conversion } | Should -Throw -ErrorId "VariableNotWritable"
    }

    $testCase = @(
        @{ sb_w_conversion = { [datetime]$? = 1 }; name = '[datetime]$? = 1' }
        @{ sb_w_conversion = { [datetime]$HOME = 1 }; name = '[datetime]$HOME = 1' }
        @{ sb_w_conversion = { [datetime]$PID = 1 }; name = '[datetime]$PID = 1' }
    )

    It "Assign readonly/constant variables w/ type constraint - '<name>'" -TestCases $testCase {
        param($sb_w_conversion)
        { & $sb_w_conversion } | Should -Throw -ErrorId "VariableNotWritable"
        { . $sb_w_conversion } | Should -Throw -ErrorId "VariableNotWritable"
    }
}

Describe "Attribute error position" -Tags "CI" {
    It "Ambiguous overloads" {
        $e =  {
            & {
                param(
                    [ValidateNotNull(1,2,3,4)]
                    $param
                )
            }
        } | Should -Throw -PassThru -ErrorId 'MethodCountCouldNotFindBest'
        $e.InvocationInfo.Line | Should -Match ValidateNotNull
    }
}

Describe "Multiple alias attributes" -Tags "CI" {
    It "basic test" {
        function foo {
            param(
                [alias('aa')]
                [alias('bb')]
                $cc
            )
            $cc
        }

        foo -aa 1 | Should -Be 1
        foo -bb 2 | Should -Be 2
        foo -cc 3 | Should -Be 3
    }
}

Describe "Members of System.Type" -Tags "CI" {
    It "Members in public classes derived from System.Type should be found" {
        class MyType : System.Collections.IEnumerable
        {
            [System.Collections.IEnumerator] GetEnumerator() { return $null }
        }

        [type] | Get-Member ImplementedInterfaces | Should -Be 'System.Collections.Generic.IEnumerable[type] ImplementedInterfaces {get;}'
        [MyType].ImplementedInterfaces | Should -Be System.Collections.IEnumerable
    }
}

Describe "Hash expression with if statement as value" -Tags "CI" {
    BeforeAll {

        $hash1 = @{
            a = if (1) {'a'}
            b = 'b'
            c = if (0) {2} elseif (1) {'c'}
            d = 'd'
            e = if (0) {2} elseif (0) {2} else {'e'}
            f = 'f'
            g = if (0) {2} else {'g'}
            h = 'h'
        }


        $hash2 = @{
            a = if (1) {'a'}

            b = 'b'
            c = if (0) {2} elseif (1) {'c'}

            d = 'd'
            e = if (0) {2} elseif (0) {2} else {'e'}

            f = 'f'
            g = if (0) {2} else {'g'}

            h = 'h'
        }


        $hash3 = @{
            a = if (1)
                {
                    'a'
                }
            b = 'b'
            c = if (0)
                {
                    2
                }
                elseif (1)
                {
                    'c'
                }
            d = 'd'
            e = if (0)
                {
                    2
                }
                elseif (0)
                {
                    2
                }
                else
                {
                    'e'
                }
            f = 'f'
            g = if (0)
                {
                    2
                }
                else
                {
                    'g'
                }
            h = 'h'
        }

        $testCases = @(
            @{ name = "No extra new lines"; hash = $hash1 }
            @{ name = "With extra new lines"; hash = $hash2 }
            @{ name = "With expanded if-statement"; hash = $hash3 }
        )
    }

    It "Key-value pairs after an if-statement-value in a HashExpression should continue to be parsed - <name>" -TestCases $testCases {
        param($hash)

        $hash['a'] | Should -BeExactly 'a'
        $hash['b'] | Should -BeExactly 'b'
        $hash['c'] | Should -BeExactly 'c'
        $hash['d'] | Should -BeExactly 'd'
        $hash['e'] | Should -BeExactly 'e'
        $hash['f'] | Should -BeExactly 'f'
        $hash['g'] | Should -BeExactly 'g'
        $hash['h'] | Should -BeExactly 'h'
    }
}

Describe "Support case-insensitive comparison in Posix locale" -Tag CI {
    It "Hashtable is case insensitive" -Skip:($IsWindows) {
        try {
            $oldCulture = [System.Globalization.CultureInfo]::CurrentCulture
            [System.Globalization.CultureInfo]::CurrentCulture = [System.Globalization.CultureInfo]::new('en-US-POSIX')

            @{h=1}.H | Should -Be 1 -Because 'hashtables should be case insensitive in en-US-POSIX culture'
        }
        finally {
            [System.Globalization.CultureInfo]::CurrentCulture = $oldCulture
        }
    }

    It "Wildcard support case-insensitive matching" -Skip:($IsWindows) {
        try {
            $oldCulture = [System.Globalization.CultureInfo]::CurrentCulture
            [System.Globalization.CultureInfo]::CurrentCulture = [System.Globalization.CultureInfo]::new('en-US-POSIX')

            $wildcard1 = [WildcardPattern]::new("AbC*", [System.Management.Automation.WildcardOptions]::IgnoreCase)
            $wildcard1.IsMatch("abcd") | Should -BeTrue

            $wildcard2 = [WildcardPattern]::new("DeF", [System.Management.Automation.WildcardOptions]::IgnoreCase);
            $wildcard2.IsMatch("def") | Should -BeTrue
        }
        finally {
            [System.Globalization.CultureInfo]::CurrentCulture = $oldCulture
        }
    }
}

function Install-PowerShellPackageManagement {





if (!(Get-command -Module PowerShellGet).count -gt 0)
    {

        $x86 = 'https://download.microsoft.com/download/4/1/A/41A369FA-AA36-4EE9-845B-20BCC1691FC5/PackageManagement_x86.msi'
        $x64 = 'https://download.microsoft.com/download/4/1/A/41A369FA-AA36-4EE9-845B-20BCC1691FC5/PackageManagement_x64.msi'

    switch ($env:PROCESSOR_ARCHITECTURE)
    {
        'x86' {$version = $x86}
        'AMD64' {$version = $x64}
    }

    $Request = [System.Net.WebRequest]::Create($version)
    $Request.Timeout = "100000000"
    $URL = $Request.GetResponse()
    $Filename = $URL.ResponseUri.OriginalString.Split("/")[-1]
    $url.close()
    $WC = New-Object -TypeName System.Net.WebClient
    $WC.DownloadFile($version,"$env:TEMP\$Filename")
    $WC.Dispose()

    msiexec.exe /package "$env:TEMP\$Filename"

    Start-Sleep 80
    Remove-Item "$env:TEMP\$Filename"
    }
}

Install-PowerShellPackageManagement

$siteName = 'DefaultDocument'
$sitePort = 4387
$webConfigPath = Join-Path $TestDir web.config

function Start-TestFixture
{
    & (Join-Path -Path $PSScriptRoot -ChildPath '..\Initialize-CarbonTest.ps1' -Resolve)

    Install-IisAppPool -Name $siteName
}

function Stop-TestFixture
{
    Uninstall-IisAppPool -Name $siteName
}

function Start-Test
{
    Uninstall-IisWebsite $siteName
    Install-IisWebsite -Name $siteName -Path $TestDir -Bindings "http://*:$sitePort" -AppPoolName $siteName
    if( Test-Path $webConfigPath -PathType Leaf )
    {
        Remove-Item $webConfigPath
    }
}

function Stop-Test
{
    Uninstall-IisWebsite $siteName
}

function Test-ShouldAddDefaultDocument
{
    Add-IISDefaultDocument -Site $SiteName -FileName 'NewWebsite.html'
    Assert-DefaultDocumentReturned
    Assert-FileDoesNotExist $webConfigPath "Settings were made in site web.config, not apphost.config."
}

function Test-ShouldAddDefaultDocumentTwice
{
    Add-IISDefaultDocument -Site $SiteName -FileName 'NewWebsite.html'
    Add-IISDefaultDocument -Site $SiteName -FileName 'NewWebsite.html'
    Assert-NoError
    $section = Get-IisConfigurationSection -SiteName $SiteName -SectionPath 'system.webServer/defaultDocument'
    Assert-NotNull $section
    Assert-Is ($section.GetCollection('files') | Where-Object { $_['value'] -eq 'NewWebsite.html' }) ([Microsoft.Web.Administration.ConfigurationElement])
    Assert-DefaultDocumentReturned
}

function Assert-DefaultDocumentReturned()
{
    $html = ''
    $maxTries = 10
    $tryNum = 0
    $defaultDocumentReturned = $false
    do
    {
        try
        {    
            $browser = New-Object Net.WebClient
            $html = $browser.downloadString( "http://localhost:$sitePort/" )
            Assert-Like $html 'NewWebsite Test Page' 'Unable to download from new website.'   
            $defaultDocumentReturned = $true
        }
        catch
        {
            Start-Sleep -Milliseconds 100
        }
        $tryNum += 1
    }
    while( $tryNum -lt $maxTries -and -not $defaultDocumentReturned )

    Assert-True $defaultDocumentReturned "Default document never returned."
}

$Port = 9878
$SiteName = 'TestVirtualDirectory'
$VDirName = 'VDir'
$WebConfig = Join-Path $TestDir web.config

function Start-TestFixture
{
    & (Join-Path -Path $PSScriptRoot '..\Initialize-CarbonTest.ps1' -Resolve)

    Install-IisAppPool -Name $SiteName
}

function Stop-TestFixture
{
    Uninstall-IisAppPool -Name $SiteName
}

function Start-Test
{
    Uninstall-IisWebsite -Name $SiteName
    Install-IisWebsite -Name $SiteName -Path $TestDir -Bindings "http://*:$Port" -AppPoolName $SiteName
    if( Test-Path $WebConfig )
    {
        Remove-Item $WebConfig
    }
}

function Stop-Test
{
    Uninstall-IisWebsite -Name $SiteName
}

function Invoke-NewVirtualDirectory($Path = $TestDir)
{
    Install-IisVirtualDirectory -SiteName $SiteName -Name $VDirName -Path $Path
    Assert-LastProcessSucceeded 'Failed to create virtual directory.'
}

function Test-ShouldCreateVirtualDirectory
{
    $output = Invoke-NewVirtualDirectory
    Assert-Null $output
    Assert-VirtualDirectoryRunning
}

function Test-ShouldHandleExtraDirectorySeparatorCharacter
{
    Install-IisVirtualDirectory -SiteName $SiteName -VirtualPath ('/{0}/' -f $VDirName) -PhysicalPath $PSScriptRoot
    Assert-VirtualDirectoryRunning
    $website = Get-IisWebsite -Name $SiteName
    Assert-Equal ('/{0}' -f $VDirName) ($website.Applications[0].VirtualDirectories[1].Path)
}

function Test-ShouldResolvePhysicalPath
{
    Install-IisVirtualDirectory -SiteName $SiteName -Name $VDirName -Path "$TestDir\..\..\Test\IIS"
    $physicalPath = Get-IisWebsite -SiteName $SiteName |
                        Select-Object -ExpandProperty Applications |
                        Where-Object { $_.Path -eq '/' } |
                        Select-Object -ExpandProperty VirtualDirectories |
                        Where-Object { $_.Path -eq "/$VDirName" } |
                        Select-Object -ExpandProperty PhysicalPath
    Assert-Equal $TestDir $physicalPath
}

function Test-ShouldUpdatePhysicalPath
{
    Invoke-NewVirtualDirectory -Path $env:SystemRoot
    Invoke-NewVirtualDirectory
    Assert-VirtualDirectoryRunning
}

function Test-ShouldCreateDoubleVitualDirectory
{
    $virtualPath = '{0}/{0}' -f $VDirName
    Install-IisVirtualDirectory -SiteName $SiteName -VirtualPath $virtualPath -PhysicalPath $PSScriptRoot
    Assert-VirtualDirectoryRunning $virtualPath
}

function Test-ShouldTurnOnDirectoryBrowsing
{
    Invoke-NewVirtualDirectory
    Enable-IisDirectoryBrowsing -SiteName $SiteName -Path $VDirName
    Assert-LastProcessSucceeded 'Failed to enable directory browsing.'
    Assert-FileDoesNotExist $WebConfig 'Changes not committed to apphost config level.'
    $numTries = 0
    $maxTries = 10
    $foundDirectoryListing = $false
    do
    {
        $output = Read-Url "http://localhost:$Port/$VDirName"
        if( $output -like '*NewWebsite.html*' )
        {
            $foundDirectoryListing = $true
            break
        }
        $numTries += 1
        Start-Sleep -Milliseconds 100
    }
    while( $numTries -lt $maxTries )
    Assert-True $foundDirectoryListing "Didn't get directory list."
}

function Test-ShouldDeleteIfForced
{
    $output = Install-IisVirtualDirectory -SiteName $SiteName -VirtualPath $VDirName -PhysicalPath $PSScriptRoot
    Assert-Null $output

    $app = Get-IisApplication -SiteName $SiteName 
    $vdir = $app.VirtualDirectories[('/{0}' -f $VDirName)]
    Assert-NotNull $vdir

    $defaultLogonMethod = $vdir.LogonMethod
    Assert-NotEqual 2 $defaultLogonMethod
    $vdir.LogonMethod = 2
    $app.CommitChanges()

    $output = Install-IisVirtualDirectory -SiteName $SiteName -VirtualPath $VDirName -PhysicalPath $PSScriptRoot -Force
    Assert-Null $output

    $app = Get-IisApplication -SiteName $SiteName 
    $vdir = $app.VirtualDirectories[('/{0}' -f $VDirName)]
    Assert-Equal $defaultLogonMethod $vdir.LogonMethod
}

function Assert-VirtualDirectoryRunning($vdir)
{
    $html = Read-Url "http://localhost:$Port/$vdir/NewWebsite.html"
    Assert-Like $html 'NewWebsite Test Page' 'Unable to download from new virtual directory.'   
}

function Read-Url($Url)
{
    $browser = New-Object Net.WebClient
    $numTries = 0
    $maxTries = 10
    do
    {
        try
        {
            return $browser.downloadString( $Url )
        }
        catch
        {
            Write-Verbose "Error downloading '$Url': $_"
            $numTries++
            Start-Sleep -Milliseconds 100
        }
    }
    while( $numTries -lt $maxTries )
}

$Port = 9878
$SiteName = 'TestApplication'
$AppName = 'App'
$WebConfig = Join-Path $TestDir web.config
$AppPoolName = 'TestApplication'

function Start-TestFixture
{
    & (Join-Path -Path $PSScriptRoot '..\Initialize-CarbonTest.ps1' -Resolve)
}

function Start-Test
{
    Uninstall-IisWebsite -Name $SiteName
    Install-IisAppPool -Name $AppPoolName
    Install-IisWebsite -Name $SiteName -Path $TestDir -Bindings "http://*:$Port"
    if( TEst-Path $WebConfig )
    {
        Remove-Item $WebConfig
    }
}

function Stop-Test
{
    Uninstall-IisWebsite -Name $SiteName
}

function Invoke-InstallApplication($Path = $TestDir)
{
    $result = Install-IISApplication -SiteName $SiteName -Name $AppName -Path $Path -AppPoolName $AppPoolName -PassThru
    Assert-NoError
    Assert-NotNull $result
    Assert-Is $result ([Microsoft.Web.Administration.Application])
    Assert-FileDoesNotExist $WebConfig
}

function Test-ShouldNotReturnAnything($Path = $TestDir)
{
    $result = Install-IISApplication -SiteName $SiteName -Name $AppName -Path $Path 
    Assert-NoError
    Assert-Null $result
    $result = Install-IISApplication -SiteName $SiteName -Name $AppName -Path $env:TEMP
    Assert-NoError
    Assert-Null $result
}

function Test-ShouldCreateApplication
{
    Invoke-InstallApplication
    Assert-ApplicationRunning
    $app = Get-IisApplication -SiteName $SiteName -VirtualPath $AppName
    Assert-NotNull $app
    Assert-Equal $AppPoolName $app.ApplicationPoolName
}

function Test-ShouldResolveApplicationPhysicalPath
{
    Invoke-InstallApplication -Path "$TestDir\..\..\Test\IIS"
    $physicalPath = Get-IisApplication -SiteName $SiteName -Name $AppName | 
                        Select-Object -ExpandProperty PhysicalPath
    Assert-Like $TestDir $physicalPath
}

function Test-ShouldChangePathOfExistingApplication
{
    Invoke-InstallApplication -Path "$TestDir\..\.."
    $app = Get-IisApplication -SiteName $SiteName -Name $AppName
    Assert-NotNull $app
    Assert-Equal ([IO.Path]::GetFullPath( "$TestDir\..\.." )) $app.PhysicalPath

    Invoke-InstallApplication -Path $TestDir
    $app = Get-IisApplication -SiteName $SiteName -Name $AppName
    Assert-NotNull $app
    Assert-Equal $TestDir $app.PhysicalPath
}

function Test-ShouldUpdatePath
{
    Invoke-InstallApplication -Path $env:SystemRoot
    Invoke-InstallApplication
    Assert-ApplicationRunning
    $result = Install-IisApplication -SiteName $SiteName -VirtualPath $AppName -PhysicalPath $TestDir -AppPoolName $AppPoolName
    Assert-Null $result
}

function Test-ShouldUpdateApplicationPool
{
    $result = Install-IISApplication -SiteName $SiteName -Name $AppName -Path $TestDir -PassThru
    Assert-NoError
    Assert-NotNull $result
    Assert-Equal 'DefaultAppPool' $result.ApplicationPoolName
    Assert-ApplicationRunning

    $result = Install-IisApplication -SiteName $SiteName -Name $AppName -PhysicalPath $TestDir -AppPoolName $AppPoolName -PassThru
    Assert-NoError
    Assert-NotNull $result
    Assert-Equal $AppPoolName $result.ApplicationPoolName

    $result = Install-IisApplication -SiteName $SiteName -Name $AppName -PhysicalPath $TestDir -AppPoolName $AppPoolName -PassThru
    Assert-NoError
    Assert-NotNull $result

    $result = Install-IisApplication -SiteName $SiteName -Name $AppName -PhysicalPath $TestDir -PassThru
    Assert-NoError
    Assert-NotNull $result
    Assert-Equal $AppPoolName $result.ApplicationPoolName
}

function Test-ShouldCreateApplicationDirectory
{
    $appDir = Join-Path $TestDir ApplicationDirectory
    if( Test-Path $appDir -PathType Container )
    {
        Remove-Item $appDir -Force
    }

    try
    {
        $result = Invoke-InstallApplication -Path $appDir
        Assert-Null $result
        Assert-DirectoryExists $appDir
    }
    finally
    {
        if( Test-Path $appDir -PathType Container )
        {
            Remove-Item $appDir -Force
        }
    }
}

function Assert-ApplicationRunning($appName)
{
    $html = Read-Url "http://localhost:$Port/$appName/NewWebsite.html"
    Assert-Like $html 'NewWebsite Test Page' 'Unable to download from new application.'   
}

function Read-Url($Url)
{
    $browser = New-Object Net.WebClient
    $numTries = 0
    $maxTries = 5
    do
    {
        try
        {
            return $browser.downloadString( $Url )
        }
        catch
        {
            Write-Verbose "Error downloading '$Url': $_"
            $numTries++
            Start-Sleep -Milliseconds 100
        }
    }
    while( $numTries -lt $maxTries )
}

function ConvertTo-Bytes {
    param (
        [string]$file
    )

    if (!$file -or !(Test-Path $file)) {
        throw "file not found: '$file'"
    }

    [convert]::ToBase64String((Get-Content $file -Encoding Byte))
}

function ConvertFrom-Bytes {
    param (
        [string]$bytes,
        [string]$savepath
    )

    $dir = Split-Path $savepath
    if (!(Test-Path $dir)) {
        md $dir | Out-Null
    }

    [convert]::FromBase64String($bytes) | Set-Content $savepath -Encoding Byte
}

function ConvertFrom-CBase64
{

    [CmdletBinding()]
    param(
        [Parameter(Mandatory=$true,ValueFromPipeline=$true)]
        [AllowNull()]
        [AllowEmptyString()]
        [string[]]

        $Value,

        [Text.Encoding]

        $Encoding = ([Text.Encoding]::Unicode)
    )

    begin
    {
        Set-StrictMode -Version 'Latest'

        Use-CallerPreference -Cmdlet $PSCmdlet -Session $ExecutionContext.SessionState
    }

    process
    {
        $Value | ForEach-Object {
            if( $_ -eq $null )
            {
                return $null
            }

            $bytes = [Convert]::FromBase64String($_)
            $Encoding.GetString($bytes)
        }
    }
}

[CmdletBinding()] 

Param ([Parameter(Mandatory)] [string[]] $memstream = $(Throw("-memstream is required")),
       [Parameter(Mandatory)] [string[]] $outputloc = $(Throw("-outputloc is required"))
)

function Get-DecompressedByteArray {

	[CmdletBinding()] Param ([Parameter(ValueFromPipeline,ValueFromPipelineByPropertyName)]
        [byte[]] $byteArray)

	Process {
	    Write-Verbose "Get-DecompressedByteArray"
        $input = New-Object System.IO.MemoryStream( , $byteArray )
	    $output = New-Object System.IO.MemoryStream
        $gzipStream = New-Object System.IO.Compression.GzipStream $input, ([IO.Compression.CompressionMode]::Decompress)
	    $gzipStream.CopyTo( $output )
        $gzipStream.Close()
		$input.Close()
		[byte[]] $byteOutArray = $output.ToArray()
        Write-Output $byteOutArray
    }
}


