function CreateStandAloneExe($Proxy, $DaisyName, $Domain) 
{
if ($Proxy) {
    $Name = "ProxyPosh"
} elseif ($DaisyName) {
    $Name = "DaisyPosh_$($DaisyName)"
} elseif ($Domain) {
    $Name = "NewPayload_$($Domain)"
