                    Task = $taskn
                    }
                    Invoke-SqliteQuery -DataSource $Database -Query $Query -SqlParameters @{
                    Task = $taskp
                    }
                    Invoke-SqliteQuery -DataSource $Database -Query $Query -SqlParameters @{
