                    startup
                } else {
                   $HelpOutput = "Error cannot find shellcode"
                    startup   
                }
            }
            elseif ($global:implantid -eq "L") 
            {
                $autorunlist = Invoke-SqliteQuery -DataSource $Database -Query "SELECT * FROM AutoRuns" -As PSObject
