﻿function Import-PSFPowerShellDataFile
{

	[Diagnostics.CodeAnalysis.SuppressMessageAttribute("PSAvoidUsingInvokeExpression", "")]
	[CmdletBinding()]
	Param (
		[Parameter(ParameterSetName = 'ByPath')]
		[string[]]
		$Path,

		[Parameter(ValueFromPipelineByPropertyName = $true, ParameterSetName = 'ByLiteralPath')]
		[Alias('PSPath')]
		[string[]]
		$LiteralPath
	)

	process
	{



		if (($ExecutionContext.Host.Runspace.InitialSessionState.LanguageMode -eq 'NoLanguage') -or ($PSVersionTable.PSVersion.Major -lt 5))
		{
			foreach ($resolvedPath in ($Path | Resolve-PSFPath -Provider FileSystem | Select-Object -Unique))
			{
				Invoke-Expression (Get-Content -Path $resolvedPath -Raw)
			}
			foreach ($pathItem in $LiteralPath)
			{
				Invoke-Expression (Get-Content -Path $pathItem -Raw)
			}
		}
		else
		{
			Import-PowerShellDataFile @PSBoundParameters
		}
	}
}

function Remove-EnvironmentVariableValue{



    [CmdletBinding()]
    param(

		[Parameter(Mandatory=$true)]
		[String]
		$Name,

		[Parameter(Mandatory=$true)]
		[String]
		$Value, 

		[Parameter(Mandatory=$true)]
		[String]
		$Target,  

		[Switch]
		$Clear  
	)  





    [Environment]::GetEnvironmentVariable($Name,$Target) | %{

        if(($_.Contains($Value) -or (Invoke-Expression "`$env:$Name").contains($Value)) -and -not $Clear){

            Write-Host "Remove value: $Value from variable: $Name"            
            $Value = $_.Trim($Value)
            [Environment]::SetEnvironmentVariable($Name, $Value,$Target)
            Invoke-Expression "`$env:$Name = `"$Value`""

        }elseif($Clear){

            Write-Host "Set value from variable: $Name to `$null"
            [Environment]::SetEnvironmentVariable($Name,$null,$Target)    
            Invoke-Expression "`$env:$Name = `$null"        
        }
    }     
}

function Get-PathAndFilename{



    [CmdletBinding()]
    param(

		[Parameter( Mandatory=$true)]
		[String]
		$Path
	)


    $Path = [System.Environment]::ExpandEnvironmentVariables($Path)


    if($Path.contains("$")){
        $Path = Invoke-Expression "`"$Path`""
    }


    if($Path.StartsWith("\")){
        $Path = Join-Path -Path $(Get-Location).Path -Childpath $Path
    }


    if(-not $Path.Contains("\")){

        $Filename = $Path
        $Path = $null

    }else{


        $ResolvedPath = $ExecutionContext.SessionState.Path.GetUnresolvedProviderPathFromPSPath($Path)
        $Path = $ResolvedPath + $(if($Path.EndsWith("\") -and -not $ResolvedPath.EndsWith("\")){"\"})


        if($Path.EndsWith("\")){

            $Filename = $null

        }else{

            $Filename = Split-Path $Path -Leaf
            $Path = Split-Path $Path -Parent         
        }
    }

    @{
        Path = $Path
        Filename = $FileName    
    }
}

