Describe 'Native UNIX globbing tests' -tags "CI" {

    BeforeAll {
        if (-Not $IsWindows )
        {
            "" > "$TESTDRIVE/abc.txt"
            "" > "$TESTDRIVE/bbb.txt"
            "" > "$TESTDRIVE/cbb.txt"
        }

        $defaultParamValues = $PSDefaultParameterValues.Clone()
        $PSDefaultParameterValues["it:skip"] = $IsWindows
    }

    AfterAll {
        $global:PSDefaultParameterValues = $defaultParamValues
    }


    It 'The globbing pattern *.txt should match 3 files' {
        (/bin/ls $TESTDRIVE/*.txt).Length | Should -Be 3
    }
    It 'The globbing pattern *b.txt should match 2 files whose basenames end in "b"' {
        (/bin/ls $TESTDRIVE/*b.txt).Length | Should -Be 2
    }

    It 'The globbing pattern should match 2 files whose names start with either "a" or "b"' {
        (/bin/ls $TESTDRIVE/[ab]*.txt).Length | Should -Be 2
    }
    It 'Globbing abc.* should return one file name "abc.txt"' {
        /bin/ls $TESTDRIVE/abc.* | Should -Match "abc.txt"
    }

    It 'Globbing [cde]b?.* should return one file name "cbb.txt"' {
        /bin/ls $TESTDRIVE/[cde]b?.* | Should -Match "cbb.txt"
    }

	It 'Globbing should work with unquoted expressions' {
	    $v = "$TESTDRIVE/abc*"
		/bin/ls $v | Should -Match "abc.txt"

		$h = [pscustomobject]@{P=$v}
		/bin/ls $h.P | Should -Match "abc.txt"

		$a = $v,$v
		/bin/ls $a[1] | Should -Match "abc.txt"
    }

    It 'Should not normalize absolute paths' {
        $matches = /bin/echo /etc/*

        $matches.substring(0,5) | Should Be '/etc/'
    }
	It 'Globbing should not happen with quoted expressions' {
	    $v = "$TESTDRIVE/abc*"
		/bin/echo "$v" | Should -BeExactly $v
		/bin/echo '$v' | Should -BeExactly '$v'
	}
    It 'Should return the original pattern (<arg>) if there are no matches' -TestCases @(
        @{arg = '/nOSuCH*file'},               
        @{arg = '/bin/nOSuCHdir/*'},           
        @{arg = '-NosUch*fIle'},               
        @{arg = '-nOsuCh*drive:nosUch*fIle'},  
        @{arg = '-nOs[u]ChdrIve:nosUch*fIle'}, 
        @{arg = '-nOsuChdRive:nosUch*fIle'},   
        @{arg = '-nOsuChdRive: nosUch*fIle'},  
        @{arg = '/no[suchFilE'},               
        @{arg = '[]'}                          
    ) {
        param($arg)
        /bin/echo $arg | Should -BeExactly $arg
    }
    $quoteTests = @(
        @{arg = '"*"'},
        @{arg = "'*'"}
    )
    It 'Should not expand quoted strings: <arg>' -TestCases $quoteTests {
        param($arg)
        Invoke-Expression "/bin/echo $arg" | Should -BeExactly '*'
    }




    It 'Should not expand quoted strings via splat array: <arg>' -TestCases $quoteTests -Skip {
        param($arg)

        function Invoke-Echo
        {
            /bin/echo @args
        }
        Invoke-Expression "Invoke-Echo $arg" | Should -BeExactly '*'
    }
    It 'Should not expand quoted strings via splat hash: <arg>' -TestCases $quoteTests -Skip {
        param($arg)

        function Invoke-Echo($quotedArg)
        {
            /bin/echo @PSBoundParameters
        }
        Invoke-Expression "Invoke-Echo -quotedArg:$arg" | Should -BeExactly "-quotedArg:*"




        Invoke-Expression "Invoke-Echo -quotedArg: $arg" | Should -BeExactly "-quotedArg:*"
    }

    It 'Should not expand patterns on non-filesystem drives' {
        /bin/echo env:ps* | Should -BeExactly "env:ps*"
    }

    It 'Globbing filenames with spaces should match 2 files' {
        "" > "$TESTDRIVE/foo bar.txt"
        "" > "$TESTDRIVE/foo baz.txt"
        (/bin/ls $TESTDRIVE/foo*.txt).Length | Should -Be 2
    }

    It 'Tilde should be replaced by the filesystem provider home directory' {
        /bin/echo ~ | Should -BeExactly ($executioncontext.SessionState.Provider.Get("FileSystem").Home)
    }

    It '~/foo should be replaced by the <filesystem provider home directory>/foo' {
        /bin/echo ~/foo | Should -BeExactly "$($executioncontext.SessionState.Provider.Get("FileSystem").Home)/foo"
    }
	It '~ should not be replaced when quoted' {
		/bin/echo '~' | Should -BeExactly '~'
		/bin/echo "~" | Should -BeExactly '~'
		/bin/echo '~/foo' | Should -BeExactly '~/foo'
		/bin/echo "~/foo" | Should -BeExactly '~/foo'
	}
}

Describe "Basic Function Provider Tests" -Tags "CI" {
    BeforeAll {
        $existingFunction = "existingFunction"
        $nonExistingFunction = "nonExistingFunction"
        $text = "Hello World!"
        $functionValue = { return $text }
        $restoreLocation = Get-Location
        $newName = "renamedFunction"
        Set-Location Function:
    }

    AfterAll {
        Set-Location -Path $restoreLocation
    }

    BeforeEach {
        Set-Item $existingFunction -Options "None" -Value $functionValue
    }

    AfterEach {
        Remove-Item $existingFunction -ErrorAction SilentlyContinue -Force
        Remove-Item $nonExistingFunction -ErrorAction SilentlyContinue -Force
        Remove-Item $newName -ErrorAction SilentlyContinue -Force
    }

    Context "Validate Set-Item Cmdlet" {
        It "Sets the new options in existing function" {
            $newOptions = "ReadOnly, AllScope"
            (Get-Item $existingFunction).Options | Should -BeExactly "None"
            Set-Item $existingFunction -Options $newOptions
            (Get-Item $existingFunction).Options | Should -BeExactly $newOptions
        }

        It "Sets the options and a value of type ScriptBlock for a new function" {
            $options = "ReadOnly"
            Set-Item $nonExistingFunction -Options $options -Value $functionValue
            $getItemResult = Get-Item $nonExistingFunction
            $getItemResult.Options | Should -BeExactly $options
            $getItemResult.ScriptBlock | Should -BeExactly $functionValue
        }

        It "Removes existing function if Set-Item has no arguments beside function name" {
            Set-Item $existingFunction
            $existingFunction | Should -Not -Exist
        }

        It "Sets a value of type FunctionInfo for a new function" {
            Set-Item $nonExistingFunction -Value (Get-Item $existingFunction)
            Invoke-Expression $nonExistingFunction | Should -BeExactly $text
        }

        It "Sets a value of type String for a new function" {
            Set-Item $nonExistingFunction -Value "return '$text' "
            Invoke-Expression $nonExistingFunction | Should -BeExactly $text
        }

        It "Throws PSArgumentException when Set-Item is called with incorrect function value" {
            { Set-Item $nonExistingFunction -Value 123 -ErrorAction Stop } | Should -Throw -ErrorId "Argument,Microsoft.PowerShell.Commands.SetItemCommand"
        }
    }

    Context "Validate Get-Item Cmdlet" {
        It "Gets existing functions by name" {
            $getItemResult = Get-Item $existingFunction
            $getItemResult.Name | Should -BeExactly $existingFunction
            $getItemResult.Options | Should -BeExactly "None"
            $getItemResult.ScriptBlock | Should -BeExactly $functionValue
        }

        It "Matches regex with stars to the function names" {
            $getItemResult = Get-Item "ex*on"
            $getItemResult.Name | Should -BeExactly $existingFunction


            $getItemResult = Get-Item "*existingFunction*"
            $getItemResult.Name | Should -BeExactly $existingFunction


            Set-Item $nonExistingFunction -Value $functionValue
            $getItemResults =  Get-Item "*Function"
            $getItemResults.Count | Should -BeGreaterThan 1
        }
    }

    Context "Validate Remove-Item Cmdlet" {
        It "Removes function" {
            Remove-Item $existingFunction
            { Get-Item $existingFunction -ErrorAction Stop } | Should -Throw -ErrorId "PathNotFound,Microsoft.PowerShell.Commands.GetItemCommand"
        }

        It "Fails to remove not existing function" {
            { Remove-Item $nonExistingFunction -ErrorAction Stop } | Should -Throw -ErrorId "PathNotFound,Microsoft.PowerShell.Commands.RemoveItemCommand"
        }
    }

    Context "Validate Rename-Item Cmdlet" {
        It "Renames existing function with None options" {
            Rename-Item $existingFunction -NewName $newName
            { Get-Item $existingFunction -ErrorAction Stop } | Should -Throw -ErrorId "PathNotFound,Microsoft.PowerShell.Commands.GetItemCommand"
            (Get-Item $newName).Count | Should -BeExactly 1
        }

        It "Fails to rename not existing function" {
            { Rename-Item $nonExistingFunction -NewName $newName -ErrorAction Stop } | Should -Throw -ErrorId "PathNotFound,Microsoft.PowerShell.Commands.RenameItemCommand"
        }

        It "Fails to rename function which is Constant" {
            Set-Item $nonExistingFunction -Options "Constant" -Value $functionValue
            { Rename-Item $nonExistingFunction -NewName $newName -ErrorAction Stop } | Should -Throw -ErrorId "CannotRenameFunction,Microsoft.PowerShell.Commands.RenameItemCommand"
        }

        It "Fails to rename function which is ReadOnly" {
            Set-Item $nonExistingFunction -Options "ReadOnly" -Value $functionValue
            { Rename-Item $nonExistingFunction -NewName $newName -ErrorAction Stop } | Should -Throw -ErrorId "CannotRenameFunction,Microsoft.PowerShell.Commands.RenameItemCommand"
        }

        It "Renames ReadOnly function when -Force parameter is on" {
            Set-Item $nonExistingFunction -Options "ReadOnly" -Value $functionValue
            Rename-Item $nonExistingFunction -NewName $newName -Force
            { Get-Item $nonExistingFunction -ErrorAction Stop } | Should -Throw -ErrorId "PathNotFound,Microsoft.PowerShell.Commands.GetItemCommand"
            (Get-Item $newName).Count | Should -BeExactly 1
        }
    }
}

Describe 'Testing of script internationalization' -Tags "CI" {
    BeforeAll {
        $dir=$PSScriptRoot
        $defaultParamValues = $PSDefaultParameterValues.Clone()

        if ($PSUICulture -ne 'en-US' -and $PSUICulture -ne 'fr-FR')
        {
            $PSDefaultParameterValues["It:Skip"] = $true
        }
    }
    AfterAll {
        $global:PSDefaultParameterValues = $defaultParamValues
    }

    It 'convertFromString-Data should work with data statement.' {

        data mydata
        {
            ConvertFrom-StringData @'
        string1=string1
        string2=string2
'@
        }

        $mydata.string1 | Should -BeExactly 'string1'
        $mydata.string2 | Should -BeExactly 'string2'
    }

    It 'Import default culture is done correctly' {

        import-localizedData mydata;

        $mydata.string1 | Should -BeExactly 'string1 for en-US'
        $mydata.string2 | Should -BeExactly 'string2 for en-US'
    }

    It 'Import specific culture(en-US)' {

        import-localizedData mydata -uiculture en-US

        $mydata.string1 | Should -BeExactly 'string1 for en-US'
        $mydata.string2 | Should -BeExactly 'string2 for en-US'

        import-localizedData mydata -uiculture fr-FR

        $mydata.string1 | Should -BeExactly 'string1 for fr-FR'
        $mydata.string2 | Should -BeExactly 'string2 for fr-FR'
    }

    It 'Import non existing culture is done correctly' {

        import-localizedData mydata -uiculture nl-NL -ErrorAction SilentlyContinue -ErrorVariable ev

        $ev | Should -Not -BeNullOrEmpty
        $ev[0].Exception | Should -BeOfType "System.Management.Automation.PSInvalidOperationException"
    }

    It 'Import different file name is done correctly' {

        import-localizedData mydata -filename foo

        $mydata.string1 | Should -BeExactly 'string1 from foo in en-US'
        $mydata.string2 | Should -BeExactly 'string2 from foo in en-US'

        import-localizedData mydata -filename foo -uiculture fr-FR

        $mydata.string1 | Should -BeExactly 'string1 from foo in fr-FR'
        $mydata.string2 | Should -BeExactly 'string2 from foo in fr-FR'
    }

    It 'Import different file base is done correctly' {

        import-localizedData mydata -basedirectory "${dir}\newbase"

        $mydata.string1 | Should -BeExactly 'string1 for en-US under newbase'
        $mydata.string2 | Should -BeExactly 'string2 for en-US under newbase'

        import-localizedData mydata -basedirectory "${dir}\newbase" -uiculture fr-FR

        $mydata.string1 | Should -BeExactly 'string1 for fr-FR under newbase'
        $mydata.string2 | Should -BeExactly 'string2 for fr-FR under newbase'
    }

    It 'Import different file base and file name' {

        import-localizedData mydata -basedirectory "${dir}\newbase" -filename foo

        $mydata.string1 | Should -BeExactly 'string1 for en-US from foo under newbase'
        $mydata.string2 | Should -BeExactly 'string2 for en-US from foo under newbase'

        import-localizedData mydata -basedirectory "${dir}\newbase" -filename foo -uiculture fr-FR

        $mydata.string1 | Should -BeExactly 'string1 for fr-FR from foo under newbase'
        $mydata.string2 | Should -BeExactly 'string2 for fr-FR from foo under newbase'
        }

    It "Import variable that doesn't exist" {

        import-localizedData mydata2

        $mydata2.string1 | Should -BeExactly 'string1 for en-US'
        $mydata2.string2 | Should -BeExactly 'string2 for en-US'
    }

    It 'Import bad psd1 file - tests the use of disallowed variables' {

        $script:exception = $null
        & {
            trap {$script:exception = $_ ; continue }
            import-localizedData mydata -filename bad
          }

        $script:exception.exception | Should -Not -BeNullOrEmpty
        $script:exception.exception | Should -BeOfType System.management.automation.psinvalidoperationexception
        }

    It 'Import if psd1 file is done correctly' {

        import-localizedData mydata -filename if

        if ($psculture -eq 'en-US')
        {
            $mydata.string1 | Should -BeExactly 'string1 for en-US in if'
            $mydata.string2 | Should -BeExactly 'string2 for en-US in if'
        }
        else
        {
            $mydata | Should -BeNullOrEmpty
        }
    }

    $testData = @(
        @{cmd = 'data d { @{ x=$(get-command)} }';Expected='get-command'},
        @{cmd = 'data d { if ($(get-command)) {} }';Expected='get-command'},
        @{cmd = 'data d { @(get-command) }';Expected='get-command'}
        )

    It 'Allowed cmdlets checked properly' -TestCase:$testData {
        param ($cmd, $Expected)

        $script:exception = $null
        & {
            trap {$script:exception = $_.Exception ; continue }
            invoke-expression $cmd
        }

        $exception | Should -Match $Expected
    }

    it 'Check alternate syntax that also supports complex variable names' {

       & {
            $script:mydata = data { 123 }
         }
        $mydata | Should -Be 123

        $mydata = data { 456 }
        & {

            import-localizedData mydata -uiculture en-US
        }
        $mydata | Should -Be 456

        & {

            import-localizedData script:mydata -uiculture en-US
        }
        $script:mydata.string1 | Should -BeExactly 'string1 for en-US'
    }

    It 'Check fallback to current directory plus -SupportedCommand parameter is done correctly' {

        new-alias MyConvertFrom-StringData ConvertFrom-StringData

        import-localizeddata local:mydata -uiculture fr-ca -filename I18n.Tests_fallback.psd1 -SupportedCommand MyConvertFrom-StringData
        $mydata[0].string1 | Should -BeExactly 'fallback string1 for en-US'
        $mydata[1] | Should -Be 42
    }
}

