function Get-ContentWithoutHeader {
    param(
        $path
    )

    $doc = Get-Content $path -Encoding UTF8
    $start = $end = -1




    for ($x = 0; $x -lt 30; $x++) {
        if ($doc[$x] -eq '---') {
            if ($start -eq -1) {
                $start = $x
            }
            else {
                if ($end -eq -1) {
                    $end = $x + 1
                    break
                }
            }
        }
    }
    if ($end -gt $start) {
        Write-Output ($doc[$end..$($doc.count)] -join ([Environment]::Newline))
    }
    else {
        Write-Output ($doc -join "`r`n")
    }
}

