function Invoke-IPv4PortScan 
{
    [CmdletBinding()]
    param(
        [Parameter(
            Position=0,
            Mandatory=$true,
            HelpMessage='ComputerName or IPv4-Address of the device which you want to scan')]
        [String]$ComputerName,

        [Parameter(
            Position=1,
            HelpMessage='First port which should be scanned (Default=1)')]
        [ValidateRange(1,65535)]
        [Int32]$StartPort=1,

        [Parameter(
            Position=2,
            HelpMessage='Last port which should be scanned (Default=65535)')]
        [ValidateRange(1,65535)]
        [ValidateScript({
            if($_ -lt $StartPort)
            {
                throw "Invalid Port-Range!"
            }
            else 
            {
                return $true
            }
        })]
        [Int32]$EndPort=65535,

        [Parameter(
            Position=3,
            HelpMessage='Maximum number of threads at the same time (Default=500)')]
        [Int32]$Threads=500,

        [Parameter(
            Position=4,
            HelpMessage='Execute script without user interaction')]
        [switch]$Force,

        [Parameter(
            Position=5,
            HelpMessage='Update Service Name and Transport Protocol Port Number Registry from IANA.org')]
        [switch]$UpdateList
    )

    Begin{
        Write-Verbose -Message "Script started at $(Get-Date)"


        $IANA_PortList_WebUri = "https://www.iana.org/assignments/service-names-port-numbers/service-names-port-numbers.xml"


        $XML_PortList_Path = "$PSScriptRoot\Resources\IANA_ServiceName_and_TransportProtocolPortNumber_Registry.xml"
        $XML_PortList_BackupPath = "$PSScriptRoot\Resources\IANA_ServiceName_and_TransportProtocolPortNumber_Registry.xml.bak"


        function UpdateListFromIANA
        {
            try{
                Write-Verbose -Message "Create backup of the IANA Service Name and Transport Protocol Port Number Registry..."


                if(Test-Path -Path $XML_PortList_Path -PathType Leaf)
                {
                    Rename-Item -Path $XML_PortList_Path -NewName $XML_PortList_BackupPath
                }

                Write-Verbose -Message "Updating Service Name and Transport Protocol Port Number Registry from IANA.org..."


                [xml]$New_XML_PortList = Invoke-WebRequest -Uri $IANA_PortList_WebUri -ErrorAction Stop

                $New_XML_PortList.Save($XML_PortList_Path)


                if(Test-Path -Path $XML_PortList_BackupPath -PathType Leaf)
                {
                    Remove-Item -Path $XML_PortList_BackupPath
                }
            }
            catch{
                Write-Verbose -Message "Cleanup downloaded file and restore backup..."


                if(Test-Path -Path $XML_PortList_Path -PathType Leaf)
                {
                    Remove-Item -Path $XML_PortList_Path -Force
                }

                if(Test-Path -Path $XML_PortList_BackupPath -PathType Leaf)
                {
                    Rename-Item -Path $XML_PortList_BackupPath -NewName $XML_PortList_Path
                }

                $_.Exception.Message  
            }
        } 


        function AssignServiceWithPort
        {
            param(
                $Result
            )

            Begin{

            }

            Process{
                $Service = [String]::Empty
                $Description = [String]::Empty

                foreach($XML_Node in $XML_PortList.Registry.Record)
                {                
                    if(($Result.Protocol -eq $XML_Node.protocol) -and ($Result.Port -eq $XML_Node.number))
                    {
                        $Service = $XML_Node.name
                        $Description = $XML_Node.description
                        break
                    }
                }

                [pscustomobject] @{
                    Port = $Result.Port
                    Protocol = $Result.Protocol
                    ServiceName = $Service
                    ServiceDescription = $Description
                    Status = $Result.Status
                }
            }  

            End{

            }
        }
    }

    Process{
        $XML_PortList_Available =Test-Path -Path $XML_PortList_Path -PathType Leaf

        if($UpdateList)
        {
            UpdateListFromIANA
        }
        elseif($XML_PortList_Available -eq $false)
        {
            Write-Warning -Message "No xml-file to assign service with port found! Use the parameter ""-UpdateList"" to download the latest version from IANA.org. This warning doesn`t affect the scanning procedure."
        }


        if($XML_PortList_Available)
        {
            $AssignServiceWithPort = $true

            $XML_PortList = [xml](Get-Content -Path $XML_PortList_Path)
        }
        else 
        {
            $AssignServiceWithPort = $false    
        }


        Write-Verbose -Message "Test if host is reachable..."
        if(-not(Test-Connection -ComputerName $ComputerName -Count 2 -Quiet))
        {
            Write-Warning -Message "$ComputerName is not reachable!"

            if($Force -eq $false)
            {
                $Title = "Continue"
                $Info = "Would you like to continue? (perhaps only ICMP is blocked)"

                $Options = [System.Management.Automation.Host.ChoiceDescription[]] @("&Yes", "&No")
                [int]$DefaultChoice = 0
                $Opt =  $host.UI.PromptForChoice($Title , $Info, $Options, $DefaultChoice)

                switch($Opt)
                {                    
                    1 { 
                        return
                    }
                }
            }
        }

        $PortsToScan = ($EndPort - $StartPort)

        Write-Verbose -Message "Scanning range from $StartPort to $EndPort ($PortsToScan Ports)"
        Write-Verbose -Message "Running with max $Threads threads"


        $IPv4Address = [String]::Empty

        if([bool]($ComputerName -as [IPAddress]))
        {
            $IPv4Address = $ComputerName
        }
        else
        {

            try{
                $AddressList = @(([System.Net.Dns]::GetHostEntry($ComputerName)).AddressList)

                foreach($Address in $AddressList)
                {
                    if($Address.AddressFamily -eq "InterNetwork") 
                    {					
                        $IPv4Address = $Address.IPAddressToString 
                        break					
                    }
                }					
            }
            catch{ }	

            if([String]::IsNullOrEmpty($IPv4Address))
            {
               throw "Could not get IPv4-Address for $ComputerName. (Try to enter an IPv4-Address instead of the Hostname)"
            }		
        }


        [System.Management.Automation.ScriptBlock]$ScriptBlock = {
            Param(
                $IPv4Address,
                $Port
            )

            try{                      
                $Socket = New-Object System.Net.Sockets.TcpClient($IPv4Address,$Port)

                if($Socket.Connected)
                {
                    $Status = "Open"             
                    $Socket.Close()
                }
                else 
                {
                    $Status = "Closed"    
                }
            }
            catch{
                $Status = "Closed"
            }   

            if($Status -eq "Open")
            {
                [pscustomobject] @{
                    Port = $Port
                    Protocol = "tcp"
                    Status = $Status
                }
            }
        }

        Write-Verbose -Message "Setting up RunspacePool..."


        $RunspacePool = [System.Management.Automation.Runspaces.RunspaceFactory]::CreateRunspacePool(1, $Threads, $Host)
        $RunspacePool.Open()
        [System.Collections.ArrayList]$Jobs = @()

        Write-Verbose -Message "Setting up Jobs..."


        foreach($Port in $StartPort..$EndPort)
        {
            $ScriptParams =@{
                IPv4Address = $IPv4Address
                Port = $Port
            }


            try {
                $Progress_Percent = (($Port - $StartPort) / $PortsToScan) * 100 
            } 
            catch { 
                $Progress_Percent = 100 
            }

            Write-Progress -Activity "Setting up jobs..." -Id 1 -Status "Current Port: $Port" -PercentComplete ($Progress_Percent)


            $Job = [System.Management.Automation.PowerShell]::Create().AddScript($ScriptBlock).AddParameters($ScriptParams)
            $Job.RunspacePool = $RunspacePool

            $JobObj = [pscustomobject] @{
                RunNum = $Port - $StartPort
                Pipe = $Job
                Result = $Job.BeginInvoke()
            }


            [void]$Jobs.Add($JobObj)
        }

        Write-Verbose -Message "Waiting for jobs to complete & starting to process results..."


        $Jobs_Total = $Jobs.Count


        Do {

            $Jobs_ToProcess = $Jobs | Where-Object -FilterScript {$_.Result.IsCompleted}


            if($null -eq $Jobs_ToProcess)
            {
                Write-Verbose -Message "No jobs completed, wait 500ms..."

                Start-Sleep -Milliseconds 500
                continue
            }


            $Jobs_Remaining = ($Jobs | Where-Object -FilterScript {$_.Result.IsCompleted -eq $false}).Count


            try {            
                $Progress_Percent = 100 - (($Jobs_Remaining / $Jobs_Total) * 100) 
            }
            catch {
                $Progress_Percent = 100
            }

            Write-Progress -Activity "Waiting for jobs to complete... ($($Threads - $($RunspacePool.GetAvailableRunspaces())) of $Threads threads running)" -Id 1 -PercentComplete $Progress_Percent -Status "$Jobs_Remaining remaining..."

            Write-Verbose -Message "Processing $(if($null -eq $Jobs_ToProcess.Count){"1"}else{$Jobs_ToProcess.Count}) job(s)..."


            foreach($Job in $Jobs_ToProcess)
            {       

                $Job_Result = $Job.Pipe.EndInvoke($Job.Result)
                $Job.Pipe.Dispose()


                $Jobs.Remove($Job)


                if($Job_Result.Status)
                {        
                    if($AssignServiceWithPort)
                    {
                        AssignServiceWithPort -Result $Job_Result
                    }   
                    else 
                    {
                        $Job_Result    
                    }             
                }
            } 

        } While ($Jobs.Count -gt 0)

        Write-Verbose -Message "Closing RunspacePool and free resources..."


        $RunspacePool.Close()
        $RunspacePool.Dispose()

        Write-Verbose -Message "Script finished at $(Get-Date)"
    }

    End{

    }
}

function Invoke-IPv4NetworkScan
{
    [CmdletBinding(DefaultParameterSetName='CIDR')]
    Param(
        [Parameter(
            ParameterSetName='Range',
            Position=0,
            Mandatory=$true,
            HelpMessage='Start IPv4-Address like 192.168.1.10')]
        [IPAddress]$StartIPv4Address,

        [Parameter(
            ParameterSetName='Range',
            Position=1,
            Mandatory=$true,
            HelpMessage='End IPv4-Address like 192.168.1.100')]
        [IPAddress]$EndIPv4Address,

        [Parameter(
            ParameterSetName='CIDR',
            Position=0,
            Mandatory=$true,
            HelpMessage='IPv4-Address which is in the subnet')]
        [Parameter(
            ParameterSetName='Mask',
            Position=0,
            Mandatory=$true,
            HelpMessage='IPv4-Address which is in the subnet')]
        [IPAddress]$IPv4Address,

        [Parameter(
            ParameterSetName='CIDR',        
            Position=1,
            Mandatory=$true,
            HelpMessage='CIDR like /24 without "/"')]
        [ValidateRange(0,31)]
        [Int32]$CIDR,

        [Parameter(
            ParameterSetName='Mask',
            Position=1,
            Mandatory=$true,
            Helpmessage='Subnetmask like 255.255.255.0')]
        [ValidateScript({
            if($_ -match "^(254|252|248|240|224|192|128).0.0.0$|^255.(254|252|248|240|224|192|128|0).0.0$|^255.255.(254|252|248|240|224|192|128|0).0$|^255.255.255.(254|252|248|240|224|192|128|0)$")
            {
                return $true
            }
            else
            {
                throw "Enter a valid subnetmask (like 255.255.255.0)!"
            }
        })]
        [String]$Mask,

        [Parameter(
            Position=2,
            HelpMessage='Maxmium number of ICMP checks for each IPv4-Address (Default=2)')]
        [Int32]$Tries=2,

        [Parameter(
            Position=3,
            HelpMessage='Maximum number of threads at the same time (Default=256)')]
        [Int32]$Threads=256,

        [Parameter(
            Position=4,
            HelpMessage='Resolve DNS for each IP (Default=Enabled)')]
        [Switch]$DisableDNSResolving,

        [Parameter(
            Position=5,
            HelpMessage='Resolve MAC-Address for each IP (Default=Disabled)')]
        [Switch]$EnableMACResolving,

        [Parameter(
            Position=6,
            HelpMessage='Get extendend informations like BufferSize, ResponseTime and TTL (Default=Disabled)')]
        [Switch]$ExtendedInformations,

        [Parameter(
            Position=7,
            HelpMessage='Include inactive devices in result')]
        [Switch]$IncludeInactive,

        [Parameter(
            Position=8,
            HelpMessage='Update IEEE Standards Registration Authority from IEEE.org (https://standards.ieee.org/develop/regauth/oui/oui.csv)')]
        [Switch]$UpdateList
    )

    Begin{
        Write-Verbose -Message "Script started at $(Get-Date)"


        $IEEE_MACVendorList_WebUri = "http://standards.ieee.org/develop/regauth/oui/oui.csv"


        $CSV_MACVendorList_Path = "$PSScriptRoot\Resources\IEEE_Standards_Registration_Authority.csv"
        $CSV_MACVendorList_BackupPath = "$PSScriptRoot\Resources\IEEE_Standards_Registration_Authority.csv.bak"


        function UpdateListFromIEEE
        {     

            try{
                Write-Verbose -Message "Create backup of the IEEE Standards Registration Authority list..."


                if(Test-Path -Path $CSV_MACVendorList_Path -PathType Leaf)
                {
                    Rename-Item -Path $CSV_MACVendorList_Path -NewName $CSV_MACVendorList_BackupPath
                }

                Write-Verbose -Message "Updating IEEE Standards Registration Authority from IEEE.org..."


                Invoke-WebRequest -Uri $IEEE_MACVendorList_WebUri -OutFile $CSV_MACVendorList_Path -ErrorAction Stop

                Write-Verbose -Message "Remove backup of the IEEE Standards Registration Authority list..."


                if(Test-Path -Path $CSV_MACVendorList_BackupPath -PathType Leaf)
                {
                    Remove-Item -Path $CSV_MACVendorList_BackupPath
                }            
            }
            catch{            
                Write-Verbose -Message "Cleanup downloaded file and restore backup..."


                if(Test-Path -Path $CSV_MACVendorList_Path)
                {
                    Remove-Item -Path $CSV_MACVendorList_Path -Force
                }

                if(Test-Path -Path $CSV_MACVendorList_BackupPath -PathType Leaf)
                {
                    Rename-Item -Path $CSV_MACVendorList_BackupPath -NewName $CSV_MACVendorList_Path
                }

                $_.Exception.Message                        
            }        
        }  


        function AssignVendorToMAC
        {
            param(
                $Result
            )

            Begin{

            }

            Process {
                $Vendor = [String]::Empty


                if(-not([String]::IsNullOrEmpty($Result.MAC)))
                {

                    $MAC_VendorSearch = $Job_Result.MAC.Replace("-","").Substring(0,6)

                    foreach($ListEntry in $MAC_VendorList)
                    {
                        if($ListEntry.Assignment -eq $MAC_VendorSearch)
                        {
                            $Vendor = $ListEntry."Organization Name"
                            break
                        }
                    }                    
                }

                [pscustomobject] @{
                    IPv4Address = $Result.IPv4Address
                    Status = $Result.Status
                    Hostname = $Result.Hostname
                    MAC = $Result.MAC
                    Vendor = $Vendor  
                    BufferSize = $Result.BufferSize
                    ResponseTime = $Result.ResponseTime
                    TTL = $Result.TTL
                }
            }

            End {

            }
        }
    }

    Process{
        $CSV_MACVendorList_Available = Test-Path -Path $CSV_MACVendorList_Path -PathType Leaf


        if($UpdateList)
        {
            UpdateListFromIEEE
        }
        elseif(($EnableMACResolving) -and ($CSV_MACVendorList_Available -eq $false))
        {
            Write-Warning -Message "No CSV-File to assign vendor with MAC-Address found! Use the parameter ""-UpdateList"" to download the latest version from IEEE.org. This warning does not affect the scanning procedure."
