function Start-PacketTrace {

	[CmdletBinding()]
	[OutputType()]
	param
	(
		[Parameter()]
		[ValidateNotNullOrEmpty()]
		[ValidateScript({ Test-Path -Path ($_ | Split-Path -Parent) -PathType Container })]
		[ValidatePattern('.*\.etl$')]
		[string[]]$TraceFilePath,
		[Parameter()]
		[switch]$Force
	)
	begin {
		Set-StrictMode -Version Latest
		$ErrorActionPreference = [System.Management.Automation.ActionPreference]::Stop
	}
	process {
		try {
			if (Test-Path -Path $TraceFilePath -PathType Leaf) {
				if (-not ($Force.IsPresent)) {
					throw "An existing trace file was found at [$($TraceFilePath)] and -Force was not used. Exiting.."
				} else {
					Remove-Item -Path $TraceFilePath
				}
			}
			$OutFile = "$PSScriptRoot\temp.txt"
			$Process = Start-Process "$($env:windir)\System32\netsh.exe" -ArgumentList "trace start persistent=yes capture=yes tracefile=$TraceFilePath" -RedirectStandardOutput $OutFile -Wait -NoNewWindow -PassThru
			if ($Process.ExitCode -notin @(0, 3010)) {
				throw "Failed to start the packet trace. Netsh exited with an exit code [$($Process.ExitCode)]"
			} else {
				Write-Verbose -Message "Successfully started netsh packet capture. Capturing all activity to [$($TraceFilePath)]"
			}
		} catch {
			Write-Error -Message "$($_.Exception.Message) - Line Number: $($_.InvocationInfo.ScriptLineNumber)"
		} finally {
			if (Test-Path -Path $OutFile -PathType Leaf) {
				Remove-Item -Path $OutFile
			}	
		}
	}
}



function Stop-PacketTrace {

	[CmdletBinding()]
	[OutputType()]
	param
	()
	begin {
		Set-StrictMode -Version Latest
		$ErrorActionPreference = [System.Management.Automation.ActionPreference]::Stop
	}
	process {
		try {
			$OutFile = "$PSScriptRoot\temp.txt"
			$Process = Start-Process "$($env:windir)\System32\netsh.exe" -ArgumentList 'trace stop' -Wait -NoNewWindow -PassThru -RedirectStandardOutput $OutFile
			if ((Get-Content $OutFile) -eq 'There is no trace session currently in progress.'){
				Write-Verbose -Message 'There are no trace sessions currently in progress'
			} elseif ($Process.ExitCode -notin @(0, 3010)) {
				throw "Failed to stop the packet trace. Netsh exited with an exit code [$($Process.ExitCode)]"
			} else {
				Write-Verbose -Message 'Successfully stopped netsh packet capture'
			}
		} catch {
			Write-Error -Message "Error: $($_.Exception.Message) - Line Number: $($_.InvocationInfo.ScriptLineNumber)"
		} finally {
			if (Test-Path -Path $OutFile -PathType Leaf) {
				Remove-Item -Path $OutFile
			}
		}
	}
}

function Install-EXEUpdates {

	Set-Variable -Name Arguments -Scope Local -Force
	Set-Variable -Name ErrCode -Scope Local -Force
	Set-Variable -Name File -Scope Local -Force
	Set-Variable -Name EXEFiles -Scope Local -Force
	Set-Variable -Name RelativePath -Scope Local -Force

	$RelativePath = (split-path $SCRIPT:MyInvocation.MyCommand.Path -parent) + "\"
	$EXEFiles = Get-ChildItem -Path $RelativePath -Force | where { $_.Name -like "*.exe*" }
	If ($EXEFiles.Count -ge 1) {
		$EXEFiles | Sort-Object
		cls
		foreach ($File in $EXEFiles) {
			$Arguments = "/passive /norestart"
			Write-Host "Installing"$File.Name"....." -NoNewline
			$ErrCode = (Start-Process -FilePath $File.Fullname -ArgumentList $Arguments -Wait -Passthru).ExitCode
			If ($ErrCode -eq 0) {
				Write-Host "Success" -ForegroundColor Yellow
			} else {
				Write-Host "Failed with error code"$ErrCode -ForegroundColor Red
			}
		}
	}


	Remove-Variable -Name Arguments -Scope Local -Force
	Remove-Variable -Name ErrCode -Scope Local -Force
	Remove-Variable -Name File -Scope Local -Force
	Remove-Variable -Name EXEFiles -Scope Local -Force
	Remove-Variable -Name RelativePath -Scope Local -Force
}

function Install-MSUUpdates {

	Set-Variable -Name Arguments -Scope Local -Force
	Set-Variable -Name ErrCode -Scope Local -Force
	Set-Variable -Name Executable -Value $env:windir"\System32\wusa.exe" -Scope Local -Force
	Set-Variable -Name File -Scope Local -Force
	Set-Variable -Name MSUFiles -Scope Local -Force
	Set-Variable -Name RelativePath -Scope Local -Force

	$RelativePath = (split-path $SCRIPT:MyInvocation.MyCommand.Path -parent) + "\"
	$MSUFiles = Get-ChildItem -Path $RelativePath -Force | where { $_.Name -like "*.msu*" }
	If ($MSUFiles.Count -ge 1) {
		$MSUFiles | Sort-Object
		cls
		foreach ($File in $MSUFiles) {
			$Arguments = $File.FullName + [char]32 + "/quiet /norestart"
			Write-Host "Installing"$File.Name"....." -NoNewline
			$ErrCode = (Start-Process -FilePath $Executable -ArgumentList $Arguments -Wait -Passthru).ExitCode
			If (($ErrCode -eq 0) -or ($ErrCode -eq 2359302)) {
				Write-Host "Success" -ForegroundColor Yellow
			} else {
				Write-Host "Failed with error code"$ErrCode -ForegroundColor Red
			}
		}
	}


	Remove-Variable -Name Arguments -Scope Local -Force
	Remove-Variable -Name ErrCode -Scope Local -Force
	Remove-Variable -Name Executable -Scope Local -Force
	Remove-Variable -Name File -Scope Local -Force
	Remove-Variable -Name MSUFiles -Scope Local -Force
	Remove-Variable -Name RelativePath -Scope Local -Force
}

cls
Install-EXEUpdates
Install-MSUUpdates
Start-Sleep -Seconds 5

Set-Variable -Name File -Scope Local -Force

