[CmdletBinding()]
param
(
		[boolean]$ListFeatures = $false,
		[string]$Feature,
		[ValidateSet('enable', 'disable')][string]$Setting,
		[String]$FeaturesFile
)

function Confirm-Feature {


	[CmdletBinding()][OutputType([boolean])]
	param
	(
			[ValidateNotNull()][string]$FeatureName,
			[ValidateSet('Enable', 'Disable')][string]$FeatureState
	)

	$WindowsFeatures = Get-WindowsFeaturesList
	$WindowsFeature = $WindowsFeatures | Where-Object { $_.Name -eq $FeatureName }
	switch ($FeatureState) {
		'Enable' {
			If (($WindowsFeature.State -eq 'Enabled') -or ($WindowsFeature.State -eq 'Enable Pending')) {
				Return $true
			} else {
				Return $false
			}
		}
		'Disable' {
			If (($WindowsFeature.State -eq 'Disabled') -or ($WindowsFeature.State -eq 'Disable Pending')) {
				Return $true
			} else {
				Return $false
			}
		}
		default {
			Return $false
		}
	}

}

function Get-WindowsFeaturesList {


	[CmdletBinding()]
	param ()

	$Temp = dism /online /get-features
	$Temp = $Temp | Where-Object { ($_ -like '*Feature Name*') -or ($_ -like '*State*') }
	$i = 0
	$Features = @()
	Do {
		$FeatureName = $Temp[$i]
		$FeatureName = $FeatureName.Split(':')
		$FeatureName = $FeatureName[1].Trim()
		$i++
		$FeatureState = $Temp[$i]
		$FeatureState = $FeatureState.Split(':')
		$FeatureState = $FeatureState[1].Trim()
		$Feature = New-Object PSObject
		$Feature | Add-Member noteproperty Name $FeatureName
		$Feature | Add-Member noteproperty State $FeatureState
		$Features += $Feature
		$i++
	} while ($i -lt $Temp.Count)
	$Features = $Features | Sort-Object Name
	Return $Features
}

function Set-WindowsFeature {


	[CmdletBinding()]
	param
	(
			[Parameter(Mandatory = $true)][ValidateNotNullOrEmpty()][string]$Name,
			[Parameter(Mandatory = $true)][ValidateSet('enable', 'disable')][string]$State
	)

	$EXE = $env:windir + "\system32\dism.exe"
	Write-Host $Name"....." -NoNewline
	If ($State -eq "enable") {
		$Parameters = "/online /enable-feature /norestart /featurename:" + $Name
	} else {
		$Parameters = "/online /disable-feature /norestart /featurename:" + $Name
	}
	$ErrCode = (Start-Process -FilePath $EXE -ArgumentList $Parameters -Wait -PassThru -WindowStyle Minimized).ExitCode
	If ($ErrCode -eq 0) {
		$FeatureChange = Confirm-Feature -FeatureName $Name -FeatureState $State
		If ($FeatureChange -eq $true) {
			If ($State -eq 'Enable') {
				Write-Host "Enabled" -ForegroundColor Yellow
			} else {
				Write-Host "Disabled" -ForegroundColor Yellow
			}
		} else {
			Write-Host "Failed" -ForegroundColor Red
		}
	} elseif ($ErrCode -eq 3010) {
		$FeatureChange = Confirm-Feature -FeatureName $Name -FeatureState $State
		If ($FeatureChange -eq $true) {
			If ($State -eq 'Enable') {
				Write-Host "Enabled & Pending Reboot" -ForegroundColor Yellow
			} else {
				Write-Host "Disabled & Pending Reboot" -ForegroundColor Yellow
			}
		} else {
			Write-Host "Failed" -ForegroundColor Red
		}
	} else {
		If ($ErrCode -eq 50) {
			Write-Host "Failed. Parent feature needs to be enabled first." -ForegroundColor Red
		} else {
			Write-Host "Failed with error code "$ErrCode -ForegroundColor Red
		}
	}
}

function Set-FeaturesFromFile {


	[CmdletBinding()]
	param ()

	$RelativePath = (split-path $SCRIPT:MyInvocation.MyCommand.Path -parent) + '\'
	$FeaturesFile = $RelativePath + $FeaturesFile
	If ((Test-Path $FeaturesFile) -eq $true) {
		$FeaturesFile = Get-Content $FeaturesFile
		foreach ($Item in $FeaturesFile) {
			$Item = $Item.split(',')
			Set-WindowsFeature -Name $Item[0] -State $Item[1]
		}
	}
}

Clear-Host
If ($ListFeatures -eq $true) {
	$WindowsFeatures = Get-WindowsFeaturesList
	$WindowsFeatures
}
If ($FeaturesFile -ne '') {
	Set-FeaturesFromFile
}
If ($Feature -ne '') {
	Set-WindowsFeature -Name $Feature -State $Setting
}

Describe "XmlCommand DRT basic functionality Tests" -Tags "CI" {

	BeforeAll {
		if(-not ('IsHiddenTestType' -as "type"))
		{
			Add-Type -TypeDefinition @"
		public class IsHiddenTestType
        {
            public IsHiddenTestType()
            {
                Property1 = 1;
                Property2 = "some string";
            }

            public IsHiddenTestType(int val, string data)
            {
                Property1 = val;
                Property2 = data;
            }

            public int Property1;
            public string Property2;
        }
"@
		}
    }

	BeforeEach {
		$testfile = Join-Path -Path $TestDrive -ChildPath "clixml-directive.xml"
	}

    AfterEach {
		remove-item $testfile -Force -ErrorAction SilentlyContinue
    }

 	It "Import with CliXml directive should work" {
        Get-Command export* -Type Cmdlet | Select-Object -First 3 | Export-Clixml -Path $testfile
		$results = Import-Clixml $testfile
		$results.Count | Should -BeExactly 3
        $results[0].PSTypeNames[0] | Should -Be "Deserialized.System.Management.Automation.CmdletInfo"
    }

	It "Import with Rehydration should work" {
		$property1 = 256
		$property2 = "abcdef"
		$isHiddenTestType = [IsHiddenTestType]::New($property1,$property2)
		$isHiddenTestType | Export-Clixml $testfile
		$results = Import-Clixml $testfile
		$results.Property1 | Should -Be $property1
		$results.Property2 | Should -Be $property2
    }

	It "Export-Clixml StopProcessing should succeed" {
        $ps = [PowerShell]::Create()
        $null = $ps.AddScript("1..10")
        $null = $ps.AddCommand("foreach-object")
        $null = $ps.AddParameter("Process", { $_; Start-Sleep -Seconds 1 })
        $null = $ps.AddCommand("Export-CliXml")
        $null = $ps.AddParameter("Path", $testfile)
        $null = $ps.BeginInvoke()
        Start-Sleep -Seconds 1
        $null = $ps.Stop()
        $ps.InvocationStateInfo.State | Should -Be "Stopped"
        $ps.Dispose()
	}

	It "Import-Clixml StopProcessing should succeed" {
		1,2,3 | Export-Clixml -Path $testfile
		$ps = [PowerShell]::Create()
		$ps.AddCommand("Get-Process")
		$ps.AddCommand("Import-CliXml")
		$ps.AddParameter("Path", $testfile)
		$ps.BeginInvoke()
		$ps.Stop()
		$ps.InvocationStateInfo.State | Should -Be "Stopped"
	}

	It "Export-Clixml using -Depth should work" {
		class Three
		{
			[int] $num = 3;
		}

		class Two
		{
			[Three] $three = [Three]::New();
			[int] $value = 2;
		}

		class One
		{
			[Two] $two = [Two]::New();
			[int] $value = 1;
		}

		$one = [One]::New()
		$one | Export-Clixml -Depth 2 -Path $testfile
		$deserialized_one = Import-Clixml -Path $testfile
		$deserialized_one.Value | Should -Be 1
		$deserialized_one.two.Value | Should -Be 2
		$deserialized_one.two.Three | Should -Not -BeNullOrEmpty
		$deserialized_one.two.three.num | Should -BeNullOrEmpty
	}

	It "Import-Clixml should work with XML serialization from pwsh.exe" {

		Start-Process -FilePath $pshome\pwsh -RedirectStandardOutput $testfile -Args "-noprofile -nologo -outputformat xml -command get-command import-clixml" -Wait
		$out = Import-Clixml -Path $testfile
		$out.Name | Should -Be "Import-CliXml"
		$out.CommandType.ToString() | Should -Be "Cmdlet"
		$out.Source | Should -Be "Microsoft.PowerShell.Utility"
	}

	It "Import-Clixml -IncludeTotalCount always returns unknown total count" {

		[PSCustomObject]@{foo=1;bar=@{hello="world"}} | Export-Clixml -Path $testfile
		$out = Import-Clixml -Path $testfile -IncludeTotalCount
		$out[0].ToString() | Should -BeExactly "Unknown total count"
	}

	It "Import-Clixml -First and -Skip work together for simple types" {
		"one","two","three","four" | Export-Clixml -Path $testfile
		$out = Import-Clixml -Path $testfile -First 2 -Skip 1
		$out.Count | Should -Be 2
		$out[0] | Should -BeExactly "two"
		$out[1] | Should -BeExactly "three"
	}

	It "Import-Clixml -First and -Skip work together for collections" {
		@{a=1;b=2;c=3;d=4} | Export-Clixml -Path $testfile

		$out1 = Import-Clixml -Path $testfile	
		$out2 = Import-Clixml -Path $testfile -First 2 -Skip 1	
		$out2.Count | Should -Be 2
        ($out2.Name) -join ":" | Should -Be (@($out1.Keys)[1, 2] -join ":")
        ($out2.Value) -join ":" | Should -Be (@($out1.Values)[1, 2] -join ":")
	}


	It "Can read back switch and parameter values using api" {
		Add-Type -AssemblyName "${pshome}/Microsoft.PowerShell.Commands.Utility.dll"

		$cmd = [Microsoft.PowerShell.Commands.ExportClixmlCommand]::new()
		$cmd.LiteralPath = "foo"
		$cmd.LiteralPath | Should -BeExactly "foo"
		$cmd.NoClobber = $true
		$cmd.NoClobber | Should -BeTrue

		$cmd = [Microsoft.PowerShell.Commands.ImportClixmlCommand]::new()
		$cmd.LiteralPath = "bar"
		$cmd.LiteralPath | Should -BeExactly "bar"

		$cmd = [Microsoft.PowerShell.Commands.SelectXmlCommand]::new()
		$cmd.LiteralPath = "foo"
		$cmd.LiteralPath | Should -BeExactly "foo"
		$xml = [xml]"<a/>"
		$cmd.Xml = $xml
		$cmd.Xml | Should -Be $xml
	}
}

﻿function Send-File
{


	[CmdletBinding()]
	param
	(
		[Parameter(Mandatory)]
		[ValidateNotNullOrEmpty()]
		[string[]]$Path,

		[Parameter(Mandatory)]
		[ValidateNotNullOrEmpty()]
		[string]$Destination,

		[Parameter(Mandatory)]
		[System.Management.Automation.Runspaces.PSSession]$Session
	)
	begin
	{
		function Test-UncPath
		{
			[CmdletBinding()]
			[OutputType([bool])]
			param
			(
				[Parameter(Mandatory)]
				[ValidateNotNullOrEmpty()]
				[string]$Path

			)
			process
			{
				if ($Path -like '\\*')
				{
					$true
				}
				else
				{
					$false
				}
			}
		}
	}
	process
	{
		foreach ($p in $Path)
		{
			try
			{
				if (Test-UncPath -Path $p)
				{
					Write-Verbose -Message "[$($p)] is a UNC path. Copying locally first"
					Copy-Item -Path $p -Destination ([environment]::GetEnvironmentVariable('TEMP', 'Machine')) -Force -Recurse
					$p = "$([environment]::GetEnvironmentVariable('TEMP', 'Machine'))\$($p | Split-Path -Leaf)"
				}
				if (Test-Path -Path $p -PathType Container)
				{
					Write-Verbose -Message "[$($p)] is a folder. Sending all files"
					$files = Get-ChildItem -Path $p -File -Recurse
					$sendFileParamColl = @()
					foreach ($file in $Files)
					{
						$sendParams = @{
							'Session' = $Session
							'Path' = $file.FullName
						}
						if ($file.DirectoryName -ne $p) 
						{
							$subdirpath = $file.DirectoryName.Replace("$p\", '')
							$sendParams.Destination = "$Destination\$subDirPath"
						}
						else
						{
							$sendParams.Destination = $Destination
						}
						$sendFileParamColl += $sendParams
					}
					foreach ($paramBlock in $sendFileParamColl)
					{
						Send-File @paramBlock
					}
				}
				else
				{
					Write-Verbose -Message "Starting WinRM copy of [$($p)] to [$($Destination)]"

					$sourceBytes = [System.IO.File]::ReadAllBytes($p);
					$streamChunks = @();


					$streamSize = 1MB;
					for ($position = 0; $position -lt $sourceBytes.Length; $position += $streamSize)
					{
						$remaining = $sourceBytes.Length - $position
						$remaining = [Math]::Min($remaining, $streamSize)

						$nextChunk = New-Object byte[] $remaining
						[Array]::Copy($sourcebytes, $position, $nextChunk, 0, $remaining)
						$streamChunks +=, $nextChunk
					}
					$remoteScript = {
						if (-not (Test-Path -Path $using:Destination -PathType Container))
						{
							$null = New-Item -Path $using:Destination -Type Directory -Force
						}
						$fileDest = "$using:Destination\$($using:p | Split-Path -Leaf)"

						$destBytes = New-Object byte[] $using:length
						$position = 0


						foreach ($chunk in $input)
						{
							[GC]::Collect()
							[Array]::Copy($chunk, 0, $destBytes, $position, $chunk.Length)
							$position += $chunk.Length
						}

						[IO.File]::WriteAllBytes($fileDest, $destBytes)

						Get-Item $fileDest
						[GC]::Collect()
					}


					$Length = $sourceBytes.Length
					$streamChunks | Invoke-Command -Session $Session -ScriptBlock $remoteScript
					Write-Verbose -Message "WinRM copy of [$($p)] to [$($Destination)] complete"
				}
			}
			catch
			{
				throw $_
			}
		}
	}

}

function Test-LocalComputer
{


	[CmdletBinding()]
	[OutputType([bool])]
	param
	(
		[Parameter(Mandatory)]
		[string]$ComputerName
	)
	begin
	{
		$LocalComputerLabels = @(
		'.',
		'localhost',
		[System.Net.Dns]::GetHostName(),
		[System.Net.Dns]::GetHostEntry('').HostName
		)
	}
	process
	{
		try
		{
			if ($LocalComputerLabels -contains $ComputerName)
			{
				Write-Verbose -Message "The computer reference [$($ComputerName)] is a local computer"
				$true
			}
			else
			{
				Write-Verbose -Message "The computer reference [$($ComputerName)] is a remote computer"
				$false
			}
		}
		catch
		{
			throw $_
		}
	}
}

function Import-CertificateSigningRequestResponse
{

	[CmdletBinding()]
	param
	(

		[Parameter(Mandatory)]
		[ValidateScript({ Test-Path -Path $_ -PathType Leaf })]
		[string]$FilePath,

		[Parameter()]
		[ValidateNotNullOrEmpty()]
		[ValidateSet('Machine', 'User')]
		[string]$CertificateLocation = 'Machine',

		[Parameter()]
		[ValidateNotNullOrEmpty()]
		[string]$ComputerName = $env:COMPUTERNAME,

		[Parameter()]
		[ValidateNotNullOrEmpty()]
		[pscredential]$Credential,

		[Parameter()]
		[ValidateNotNullOrEmpty()]
		[string]$CertReqFilePath = "$env:SystemRoot\system32\certreq.exe"
	)
	process
	{
		try
		{
			if (-not (Test-LocalComputer -ComputerName $ComputerName))
			{
				$sessParams = @{
					'ComputerName' = $ComputerName
				}

				$remoteFilePath = "C:\$([System.IO.Path]::GetFileName($FilePath))"
				$session = New-PSSession @sessParams

				$null = Send-File -Session $session -Path $FilePath -Destination 'C:\'

				Invoke-Command -Session $session -ScriptBlock { Start-Process -FilePath $using:CertReqFilePath -Args "-accept -$using:CertificateLocation `"$using:remoteFilePath`""}
			}
			else
			{
				Start-Process -FilePath $CertReqFilePath -Args "-accept -$CertificateLocation `"$FilePath`"" -Wait -NoNewWindow
			}
		}
		catch
		{
			throw $_
		}
		finally
		{
			Invoke-Command -Session $session -ScriptBlock {Remove-Item -Path $using:remoteFilePath -ErrorAction Ignore}
			Remove-PSSession -Session $session -ErrorAction Ignore
		}
	}
}

function Get-UserSession {

    [cmdletbinding()]
    Param(
        [Parameter(
            Position = 0,
            ValueFromPipeline = $True)]
        [string[]]$computername = "localhost",

        [switch]$parseIdleTime,

        [validaterange(0,120)]$timeout = 15
    )             

    ForEach($computer in $computername) {




                Do{
                    $tempFile = [System.IO.Path]::GetTempFileName()
                    start-sleep -Milliseconds 300
                }
                Until(test-path $tempfile)


                $startTime = Get-Date
                $p = Start-Process -FilePath C:\windows\system32\cmd.exe -ArgumentList "/c query user /server:$computer > $tempfile" -WindowStyle hidden -passthru



                $stopprocessing = $false
                do{


                    $hasExited = $p.HasExited


                    Try { $proc = get-process -id $p.id -ErrorAction stop }
                    Catch { $proc = $null }


                    start-sleep -seconds .5


                    if( ( (Get-Date) - $startTime ).totalseconds -gt $timeout -and -not $hasExited -and $proc){
                        $p.kill()
                        $stopprocessing = $true
                        remove-item $tempfile -force
                        Write-Error "$computer`: Query.exe took longer than $timeout seconds to execute"
                    }
                }
                until($hasexited -or $stopProcessing -or -not $proc)
                if($stopprocessing){ Continue }


                $sessions = get-content $tempfile
                remove-item $tempfile -force


        if($sessions){

            1..($sessions.count -1) | % {


                $temp = "" | Select ComputerName, Username, SessionName, Id, State, IdleTime, LogonTime
                $temp.ComputerName = $computer





                if($sessions[$_].length -gt 5){

                    if($sessions[$_].length -le 82){

                        $temp.Username = $sessions[$_].Substring(1,22).trim()
                        $temp.SessionName = $sessions[$_].Substring(23,19).trim()
                        $temp.Id = $sessions[$_].Substring(42,4).trim()
                        $temp.State = $sessions[$_].Substring(46,8).trim()
                        $temp.IdleTime = $sessions[$_].Substring(54,11).trim()
                        $logonTimeLength = $sessions[$_].length - 65
                        try{
                            $temp.LogonTime = get-date $sessions[$_].Substring(65,$logonTimeLength).trim()
                        }
                        catch{
                            $temp.LogonTime = $sessions[$_].Substring(65,$logonTimeLength).trim() | out-null
                        }

                    }

                    else{                                       
                        $array = $sessions[$_] -replace "\s+", " " -split " "
                        $temp.Username = $array[1]


                        if($array.count -lt 9){
                            $temp.SessionName = ""
                            $temp.Id = $array[2]
                            $temp.State = $array[3]
                            $temp.IdleTime = $array[4]
                            $temp.LogonTime = get-date $($array[5] + " " + $array[6] + " " + $array[7])
                        }
                        else{
                            $temp.SessionName = $array[2]
                            $temp.Id = $array[3]
                            $temp.State = $array[4]
                            $temp.IdleTime = $array[5]
                            $temp.LogonTime = get-date $($array[6] + " " + $array[7] + " " + $array[8])
                        }
                    }


                    if($parseIdleTime){
                        $string = $temp.idletime


                        function convert-shortIdle {
                            param($string)
                            if($string -match "\:"){
                                [timespan]$string
                            }
                            else{
                                New-TimeSpan -minutes $string
                            }
                        }


                        if($string -match "\+"){
                            $days = new-timespan -days ($string -split "\+")[0]
                            $hourMin = convert-shortIdle ($string -split "\+")[1]
                            $temp.idletime = $days + $hourMin
                        }

                        elseif($string -like "." -or $string -like "none"){
                            $temp.idletime = [timespan]"0:00"
                        }

                        else{
                            $temp.idletime = convert-shortIdle $string
                        }
                    }


                    $temp
                }
            }
        }            
        else{ Write-warning "$computer`: No sessions found" }
    }
}

Describe "Start-Process" -Tag "Feature","RequireAdminOnWindows" {

    BeforeAll {
        $isNanoServer = [System.Management.Automation.Platform]::IsNanoServer
        $isIot = [System.Management.Automation.Platform]::IsIoT
        $isFullWin = $IsWindows -and !$isNanoServer -and !$isIot
        $extraArgs = @{}
        if ($isFullWin) {
            $extraArgs.WindowStyle = "Hidden"
        }

        $pingCommand = (Get-Command -CommandType Application ping)[0].Definition
        $pingDirectory = Split-Path $pingCommand -Parent
        $tempFile = Join-Path -Path $TestDrive -ChildPath PSTest
        $assetsFile = Join-Path -Path (Join-Path -Path $PSScriptRoot -ChildPath assets) -ChildPath SortTest.txt
        if ($IsWindows) {
            $pingParam = "-n 2 localhost"
        }
        elseif ($IsLinux -Or $IsMacOS) {
	        $pingParam = "-c 2 localhost"
        }
    }




    It "Should process arguments without error" {
	    $process = Start-Process ping -ArgumentList $pingParam -PassThru -RedirectStandardOutput "$TESTDRIVE/output" @extraArgs

	    $process.Length      | Should -Be 1
	    $process.Id          | Should -BeGreaterThan 1

    }

    It "Should work correctly when used with full path name" {
	    $process = Start-Process $pingCommand -ArgumentList $pingParam -PassThru -RedirectStandardOutput "$TESTDRIVE/output"  @extraArgs

	    $process.Length      | Should -Be 1
	    $process.Id          | Should -BeGreaterThan 1

    }

    It "Should invoke correct path when used with FilePath argument" {
	    $process = Start-Process -FilePath $pingCommand -ArgumentList $pingParam -PassThru -RedirectStandardOutput "$TESTDRIVE/output" @extraArgs

	    $process.Length      | Should -Be 1
	    $process.Id          | Should -BeGreaterThan 1

    }

    It "Should invoke correct path when used with Path alias argument" {
	    $process = Start-Process -Path $pingCommand -ArgumentList $pingParam -PassThru -RedirectStandardOutput "$TESTDRIVE/output" @extraArgs

	    $process.Length | Should -Be 1
	    $process.Id     | Should -BeGreaterThan 1
    }

    It "Should wait for command completion if used with Wait argument" {
	    $process = Start-Process ping -ArgumentList $pingParam -Wait -PassThru -RedirectStandardOutput "$TESTDRIVE/output" @extraArgs
    }

    It "Should work correctly with WorkingDirectory argument" {
	    $process = Start-Process ping -WorkingDirectory $pingDirectory -ArgumentList $pingParam -PassThru -RedirectStandardOutput "$TESTDRIVE/output" @extraArgs

	    $process.Length      | Should -Be 1
	    $process.Id          | Should -BeGreaterThan 1

    }

    It "Should handle stderr redirection without error" {
	    $process = Start-Process ping -ArgumentList $pingParam -PassThru -RedirectStandardError $tempFile -RedirectStandardOutput "$TESTDRIVE/output"  @extraArgs

	    $process.Length      | Should -Be 1
	    $process.Id          | Should -BeGreaterThan 1

    }

    It "Should handle stdout redirection without error" {
	    $process = Start-Process ping -ArgumentList $pingParam -Wait -RedirectStandardOutput $tempFile  @extraArgs
	    $dirEntry = get-childitem $tempFile
	    $dirEntry.Length | Should -BeGreaterThan 0
    }


    It "Should handle stdin redirection without error" -Pending {
	    $process = Start-Process sort -Wait -RedirectStandardOutput $tempFile -RedirectStandardInput $assetsFile  @extraArgs
	    $dirEntry = get-childitem $tempFile
	    $dirEntry.Length | Should -BeGreaterThan 0
    }


    It "Should give an error when -Verb parameter is used" -Skip:$isFullWin {
        { Start-Process -Verb runas -FilePath $pingCommand } | Should -Throw -ErrorId "NotSupportedException,Microsoft.PowerShell.Commands.StartProcessCommand"
    }


    It "Should give an error when -WindowStyle parameter is used" -Skip:$isFullWin {
        { Start-Process -FilePath $pingCommand -WindowStyle Normal } | Should -Throw -ErrorId "NotSupportedException,Microsoft.PowerShell.Commands.StartProcessCommand"
    }

    It "Should give an error when both -NoNewWindow and -WindowStyle are specified" -Skip:(!$isFullWin) {
        { Start-Process -FilePath $pingCommand -NoNewWindow -WindowStyle Normal -ErrorAction Stop } | Should -Throw -ErrorId "InvalidOperationException,Microsoft.PowerShell.Commands.StartProcessCommand"
    }

    It "Should start cmd.exe with Verb 'open' and WindowStyle 'Minimized'" -Skip:(!$isFullWin) {
        $fileToWrite = Join-Path $TestDrive "VerbTest.txt"
        $process = Start-Process cmd.exe -ArgumentList "/c echo abc > $fileToWrite" -Verb open -WindowStyle Minimized -PassThru
        $process.Name | Should -Be "cmd"
        $process.WaitForExit()
        Test-Path $fileToWrite | Should -BeTrue
    }

    It "Should start notepad.exe with ShellExecute" -Skip:(!$isFullWin) {
        $process = Start-Process notepad.exe -PassThru -WindowStyle Normal
        $process.Name | Should -Be "notepad"
        $process | Stop-Process
    }

    It "Should be able to use the -WhatIf switch without performing the actual action" {
        $pingOutput = Join-Path $TestDrive "pingOutput.txt"
        { Start-Process -Wait $pingCommand -ArgumentList $pingParam -RedirectStandardOutput $pingOutput -WhatIf -ErrorAction Stop  @extraArgs} | Should -Not -Throw
        $pingOutput | Should -Not -Exist
    }

    It "Should return null when using -WhatIf switch with -PassThru" {
        Start-Process $pingCommand -ArgumentList $pingParam -PassThru -WhatIf | Should -BeNullOrEmpty
    }

    It 'Should run without errors when -ArgumentList is $null' {
         $process = Start-Process $pingCommand -ArgumentList $null -PassThru @extraArgs
         $process.Length      | Should -Be 1
         $process.Id          | Should -BeGreaterThan 1
    }

    It "Should run without errors when -ArgumentList is @()" {
        $process = Start-Process $pingCommand -ArgumentList @() -PassThru @extraArgs
        $process.Length      | Should -Be 1
        $process.Id          | Should -BeGreaterThan 1
    }

    It "Should run without errors when -ArgumentList is ''" {
        $process = Start-Process $pingCommand -ArgumentList '' -PassThru @extraArgs
        $process.Length      | Should -Be 1
        $process.Id          | Should -BeGreaterThan 1
    }
}

Describe "Start-Process tests requiring admin" -Tags "Feature","RequireAdminOnWindows" {

    BeforeEach {
        cmd /c assoc .foo=foofile
        cmd /c ftype foofile=cmd /c echo %1^> $testdrive\foo.txt
        Remove-Item $testdrive\foo.txt -Force -ErrorAction SilentlyContinue
    }

    AfterEach {
        cmd /c assoc .foo=
        cmd /c ftype foofile=
    }

    It "Should open the application that is associated a file" -Skip:(!$isFullWin) {
        $fooFile = Join-Path $TestDrive "FooTest.foo"
        New-Item $fooFile -ItemType File -Force
        Start-Process $fooFile

        Wait-FileToBePresent -File "$testdrive\foo.txt" -TimeoutInSeconds 10 -IntervalInMilliseconds 100 | Should -BeTrue
        Get-Content $testdrive\foo.txt | Should -BeExactly $fooFile
    }
}








Clear-Host  

Set-Variable -Name OS -Scope Global -Force  
Set-Variable -Name RelativePath -Scope Global -Force  
Function RenameWindow ($Title) {  

     Set-Variable -Name a -Scope Local -Force  
     $a = (Get-Host).UI.RawUI  
     $a.WindowTitle = $Title  

     Remove-Variable -Name a -Scope Local -Force  
}  
Function GetRelativePath {  
     $Global:RelativePath=(split-path $SCRIPT:MyInvocation.MyCommand.Path -parent)+"\"  
}  
Function GetOSArchitecture {  
     $Global:Architecture = Get-WMIObject win32_operatingsystem  
     $Global:Architecture = $Global:Architecture.OSArchitecture  

}  
Function ProcessRunning($Description,$Process) {  

     Set-Variable -Name ProcessActive -Scope Local -Force  
     Write-Host $Description"....." -NoNewline  
     $ProcessActive = Get-Process $Process -ErrorAction SilentlyContinue  
     if($ProcessActive -eq $null) {  
          Write-Host "Not Running" -ForegroundColor Yellow  
     } else {  
          Write-Host "Running" -ForegroundColor Red  
     }  

     Remove-Variable -Name ProcessActive -Scope Local -Force  
}  
Function KillProcess($Description,$Process) {  

     Set-Variable -Name ProcessActive -Scope Local -Force  
     Write-Host $Description"....." -NoNewline  
     $ProcessActive = Stop-Process -Name $Process -Force  
     If ($ProcessActive -eq $null) {  
          Write-Host "Killed" -ForegroundColor Yellow  
     } else {  
          Write-Host "Still Running" -ForegroundColor Red  
     }  
}  
Function CopyFile($FileName,$SourceDir,$DestinationDir,$NewFileName) {  
     If ($SourceDir.SubString($SourceDir.length-1) -ne "\") {  
          $SourceDir = $SourceDir+"\"  
     }  
     If ((Test-Path -Path $SourceDir$FileName) -eq $true) {  
          Write-Host "Copying"$FileName"....."  
          Copy-Item -Path $SourceDir$FileName -Destination $DestinationDir -Force  
          If ($NewFileName -ne "") {  
               If ($DestinationDir.SubString($DestinationDir.length-1) -ne "\") {  
                    $DestinationDir = $DestinationDir+"\"  
               }  
               Rename-Item -Path $DestinationDir$FileName -NewName $NewFileName -Force  
          }  
     }  
}  
Function BalloonTip($ApplicationName, $Status, $DisplayTime) {  

     Set-Variable -Name balloon -Scope Local -Force  
     Set-Variable -Name icon -Scope Local -Force  
     Set-Variable -Name path -Scope Local -Force  
     [system.Reflection.Assembly]::LoadWithPartialName('System.Windows.Forms') | Out-Null  
     $balloon = New-Object System.Windows.Forms.NotifyIcon  
     $path = Get-Process -id $pid | Select-Object -ExpandProperty Path  
     $icon = [System.Drawing.Icon]::ExtractAssociatedIcon($path)  
     $balloon.Icon = $icon  
     $balloon.BalloonTipIcon = 'Info'  
     $balloon.BalloonTipTitle = "Gresham, Smith and Partners"  
     $balloon.BalloonTipText = $ApplicationName+[char]13+[char]13+$Status  
     $balloon.Visible = $true  
     $balloon.ShowBalloonTip($DisplayTime)  

     Remove-Variable -Name balloon -Scope Local -Force  
     Remove-Variable -Name icon -Scope Local -Force  
     Remove-Variable -Name path -Scope Local -Force  
}  
Function UninstallOldMSIApplication($Description) {  

     Set-Variable -Name AppName -Scope Local -Force  
     Set-Variable -Name Arguments -Scope Local -Force  
     Set-Variable -Name Desc -Scope Local -Force  
     Set-Variable -Name ErrCode -Scope Local -Force  
     Set-Variable -Name GUID -Scope Local -Force  
     Set-Variable -Name Output -Scope Local -Force  
     Set-Variable -Name Output1 -Scope Local -Force  

     $Desc = [char]34+"description like"+[char]32+[char]39+[char]37+$Description+[char]37+[char]39+[char]34  
     $Output1 = wmic product where $Desc get Description  
     cls  
     $Output1 | ForEach-Object {  
          $_ = $_.Trim()  
       if(($_ -ne "Description")-and($_ -ne "")){  
         $AppName = $_  
       }  
     }  
     If ($AppName -eq $null) {  
          return  
     }  
     Write-Host "Uninstalling"$AppName"....." -NoNewline  
     $Output = wmic product where $Desc get IdentifyingNumber  
     $Output | ForEach-Object {  
          $_ = $_.Trim()  
            if(($_ -ne "IdentifyingNumber")-and($_ -ne "")){  
              $GUID = $_  
            }  
     }  
     $Arguments = "/X"+[char]32+$GUID+[char]32+"/qb- /norestart"  
     $ErrCode = (Start-Process -FilePath "msiexec.exe" -ArgumentList $Arguments -Wait -Passthru).ExitCode  
     $Result = (AppInstalled $Description)  
     If ($Result) {  
          Write-Host "Failed with error code"$ErrCode -ForegroundColor Red  
     } else {  
          Write-Host "Uninstalled" -ForegroundColor Yellow  
     }  

     Remove-Variable -Name AppName -Scope Local -Force  
     Remove-Variable -Name Arguments -Scope Local -Force  
     Remove-Variable -Name Desc -Scope Local -Force  
     Remove-Variable -Name ErrCode -Scope Local -Force  
     Remove-Variable -Name GUID -Scope Local -Force  
     Remove-Variable -Name Output -Scope Local -Force  
     Remove-Variable -Name Output1 -Scope Local -Force  
}  
Function InstallMSIApplication($App,$Switches,$Transforms,$Desc) {  

     Set-Variable -Name App -Scope Local -Force  
     Set-Variable -Name Arguments -Scope Local -Force  
     Set-Variable -Name ErrCode -Scope Local -Force  
     Set-Variable -Name Result -Scope Local -Force  
     Write-Host "Installing"$Desc"....." -NoNewline  
     $App = [char]32+[char]34+$RelativePath+$App+[char]34  
     $Switches = [char]32+$Switches  
     If ($Transforms -ne $null) {  
          $Transforms = [char]32+"TRANSFORMS="+$RelativePath+$Transforms  
          $Arguments = "/I"+$App+$Transforms+$Switches  
     } else {  
          $Arguments = "/I"+$App+$Switches  
     }  
     $ErrCode = (Start-Process -FilePath "msiexec.exe" -ArgumentList $Arguments -Wait -Passthru).ExitCode  
     $Result = (AppInstalled $Desc)  
     If ($Result) {  
          Write-Host "Installed" -ForegroundColor Yellow  
     } else {  
          Write-Host "Failed with error"$ErrCode -ForegroundColor Red  
     }  

     Remove-Variable -Name App -Scope Local -Force  
     Remove-Variable -Name Arguments -Scope Local -Force  
     Remove-Variable -Name ErrCode -Scope Local -Force  
     Remove-Variable -Name Result -Scope Local -Force  
}  
Function InstallEXEApplication($App,$Switches,$Desc) {  

     Set-Variable -Name ErrCode -Scope Local -Force  
     Set-Variable -Name Result -Scope Local -Force  
     Write-Host "Installing <Application>....." -NoNewline  
     $App = [char]32+[char]34+$RelativePath+$App+[char]34  
     $ErrCode = (Start-Process -FilePath $App -ArgumentList $Switches -Wait -Passthru).ExitCode  
     $Result = (AppInstalled $Desc)  
     If ($Result) {  
          Write-Host "Installed" -ForegroundColor Yellow  
     } else {  
          Write-Host "Failed with error"$ErrCode -ForegroundColor Red  
     }  

     Remove-Variable -Name ErrCode -Scope Local -Force  
     Remove-Variable -Name Result -Scope Local -Force  
}  
Function AppInstalled($Description) {  

     Set-Variable -Name AppName -Scope Local -Force  
     Set-Variable -Name Output -Scope Local -Force  

     $Description = [char]34+"description like"+[char]32+[char]39+[char]37+$Description+[char]37+[char]39+[char]34  
     $Output = wmic product where $Description get Description  
     $Output | ForEach-Object {  
          $_ = $_.Trim()  
            if(($_ -ne "Description")-and($_ -ne "")){  
               $AppName = $_  
            }  
     }  
     If ($AppName -eq $null) {  
          return $false  
     } else {  
          return $true  
     }  

     Remove-Variable -Name AppName -Scope Local -Force  
     Remove-Variable -Name Output -Scope Local -Force  
}  
Function ExecuteDCSU($App,$Switches) {  

     Set-Variable -Name ErrCode -Scope Local -Force  
     $App = [char]34+"C:\Program Files (x86)\Dell\ClientSystemUpdate\"+$App+[char]34  
     $Switches = "/policy"+[char]32+$RelativePath+$Switches  
     $ErrCode = (Start-Process -FilePath $App -ArgumentList $Switches -Wait -Passthru).ExitCode  
     If ($ErrCode -eq 0) {  
          Write-Host "Drivers Updated" -ForegroundColor Yellow  
     } else {  
          Write-Host "Failed with error"$ErrCode -ForegroundColor Red  
     }  

     Remove-Variable -Name ErrCode -Scope Local -Force  
}  
